// ===== datatools/Pattern.hh =====
#include <string>
#include <vector>
#include <iostream>
#include <cstdlib>

namespace DataTools {
/**A class representing a pattern. A pattern consists of two elements.
 * (i)The data point i.e. input to the classifier.
 * (ii)The classification i.e. the target output of the classifier.
 */
class Pattern {
  public:
	/**Basic constructor.
	 * \param id the identification string for this pattern.
	 * \param in the input portion of the pattern.
	 * \param out the output portion of the pattern.
	 */
	Pattern(std::string id, std::vector<double>& in, std::vector<double>& out);

	/**Empty constructor. */
	Pattern();

	/**Copy constructor.
	 * \param pattern the pattern to copy from.
	 */
	Pattern(const Pattern& pattern);

	/**The destructor. */
	~Pattern();

	/**Assignment operator.
	 * \param pattern the Pattern to assign from.
	 */
	Pattern& operator=(const Pattern& pattern);

	/**Returns the identification string for this pattern.
	 * \return the identification string.
	 */
	std::string& idstring();

	/**Sets the identification string for this pattern.
	 * \param id the identification string to use.
	 */
	void idstring(const std::string& id);

	/**Returns the input vector. */
	std::vector<double>& input();

	/**Sets the input vector.
	 * \param in the input vector to use.
	 */
	void input(std::vector<double>& in);

	/**Fetch the number of inputs this pattern uses.
	 * \return the number of inputs.
	 */
	uint nInput() const;

	/**Returns the output vector.
	 * \return the output vector.
	 */
	std::vector<double>& output();

	/**Sets the output vector.
	 * \param out the output vector to use.
	 */
	void output(std::vector<double>& out);

	/**Return the number of outputs this pattern uses.
	 * \return the number of outputs.
	 */
	uint nOutput() const;

	/**Print this pattern. */
	void print(std::ostream& os) const;

  private:
	/**The identification string of this pattern. */
	std::string id;

	/**The input portion of this pattern. */
	std::vector<double> in;

	/**The output portion of this pattern. */
	std::vector<double> out;
};

inline std::string& Pattern::idstring() {
	return id;
}
inline void Pattern::idstring(const std::string& id) {
	this->id = id;
}
} // namespace DataTools

// ===== datatools/CoreDataSet.hh =====
#include <vector>
#include <iostream>

namespace DataTools {
/**A class representing data storage.
 * \sa DataSet, Pattern
 */
class CoreDataSet {
  public:
	/**Basic constructor. */
	CoreDataSet();

	/**Copy constructor.
	 * \param coreDataSet the data set to copy from.
	 */
	CoreDataSet(const CoreDataSet& coreDataSet);

	/**Basic destructor. */
	~CoreDataSet();

	/**Assignment operator.
	 * \param coreDataSet the data set to assign from.
	 */
	CoreDataSet& operator=(const CoreDataSet& coreDataSet);

	/**Returns the pattern at index.
	 * \param index the index for the pattern to fetch.
	 * \return the specified pattern.
	 */
	Pattern& pattern(uint index);

	/**Fetch all patterns residing in this CoreDataSet stored in a vector.
	 * \return the pattern vector.
	 */
	std::vector<Pattern>& patternVector();

	/**Adds a pattern to this data set.
	 * \param pattern the pattern to add.
	 */
	void addPattern(const Pattern& pattern);

	/**Fetch the number of inputs a pattern uses.
	 * \return the number of inputs.
	 */
	uint nInput() const;

	/**Fetch the number of outputs a pattern uses.
	 * \return the number of outputs.
	 */
	uint nOutput() const;

	/**Return the number of patterns residing in this data set.
	 * \return the total number of patterns.
	 */
	uint size() const;

	/**Print the data set to output stream.
	 * \param os the output stream to print to.
	 */
	void print(std::ostream& os) const;

  private:
	/**Holds the patterns. */
	std::vector<Pattern> patterns;

	/**The patterns iterator. */
	std::vector<Pattern>::iterator itp;
};
} // namespace DataTools

// ===== datatools/DataSet.hh =====
#include <iostream>
#include <memory>
#include <vector>

namespace DataTools {
/**A view layer over a CoreDataSet. Each DataSet holds a `shared_ptr` to the
 * underlying CoreDataSet plus its own index vector, so multiple views (train
 * splits, bootstrap samples, etc.) can share the same underlying patterns
 * without copying them.
 *
 * Lifetime is automatic: the CoreDataSet is destroyed when the last DataSet
 * referencing it goes out of scope.
 *
 * \sa CoreDataSet, Pattern
 */
class DataSet {
  public:
	DataSet();
	DataSet(const DataSet& dataSet);
	DataSet(DataSet&&) noexcept = default;
	~DataSet();
	DataSet& operator=(const DataSet& dataSet);
	DataSet& operator=(DataSet&&) noexcept = default;

	/**Return the indices mapping this DataSet to the CoreDataSet. */
	std::vector<uint>& indices();

	/**Set the indices mapping this DataSet to the CoreDataSet. */
	void indices(std::vector<uint>& i);

	/**Return the pattern at index. */
	Pattern& pattern(uint index);

	/**Reference to the underlying CoreDataSet. */
	CoreDataSet& coreDataSet();

	/**Bind this DataSet to a CoreDataSet. Resets indices to {0, 1, ..., N-1}.
	 *
	 * Pass a `std::shared_ptr<CoreDataSet>` so ownership is unambiguous and
	 * the data outlives every DataSet that views it. Use
	 * `std::make_shared<CoreDataSet>()` to construct one.
	 */
	void coreDataSet(std::shared_ptr<CoreDataSet> cds);

	/**Return the shared_ptr to the underlying CoreDataSet. Useful for
	 * building another DataSet view onto the same data.
	 */
	std::shared_ptr<CoreDataSet> sharedCoreDataSet() const;

	uint nInput() const;
	uint nOutput() const;
	uint size() const;
	void print(std::ostream& os) const;

  private:
	std::vector<uint> theIndices;
	std::vector<uint>::iterator itp;
	std::shared_ptr<CoreDataSet> theCoreDataSet;
};
} // namespace DataTools

// ===== ModelSelector.hh =====
#include <vector>
#include <utility>

namespace NeuralNetHack {
/**Selecting the optimal model by performing a grid search over the chosen
 * parameters.
 */
class ModelSelector {
  public:
	ModelSelector();
	virtual ~ModelSelector();
	std::pair<Config, double> findBestModel(DataTools::DataSet& trnData, Config& config);

  private:
	/** Method for constructing a full sequence from a vector seq.
	 * \param seq vector containing the start stop and increment value.
	 */
	std::vector<double> sequence(const std::vector<double>& seq);

	std::pair<double, double>* trainAndValidateModel(DataTools::DataSet& trnData,
	                                                 const Config& config);

	/** Calculate the .632+ rule.
	 * \param gamma The no-information error rate. For AUC it's 0.5.
	 * \param meanTrn The mean training performance over the bootstrap samples.
	 * \param meanTst The mean testing performance over the bootstrap samples.
	 */
	double Auc632PlusRule(double meanTrn, double meanTst);
};
} // namespace NeuralNetHack

