namespace DataTools {
/**A class representing splitting one large DataSet into K DataSet(s).
 * Both bootstrap and cross-splitting is possible.
 * This can be done sequentially or randomised.
 * \sa DataSet
 */
class DataManager {
  public:
	/**Basic constructor. */
	DataManager();

	/**Copy constructor.
	 * \param ds the DataManager to copy from.
	 */
	DataManager(const DataManager& ds);

	/**Basic destructor. */
	~DataManager();

	/**Assignment operator.
	 * \param ds the DataManager to assign from.
	 * \return the new DataManager.
	 */
	DataManager& operator=(const DataManager& ds);

	/**Get state of the data selection mode.
	 * \return true if randomised data split is on, false otherwise.
	 */
	bool random() const;

	/**Set state of the data selection mode.
	 * \param rnd controlling randomised split on/off.
	 */
	void random(bool rnd);

	/**Split the DataSet into two disjuctive parts (training, validation).
	 * \param ds the DataSet to split.
	 * \param ratio the fraction of patterns going to training.
	 */
	std::pair<DataSet, DataSet> split(DataSet& ds, double ratio);

	/**Split the DataSet into k disjunctive parts. */
	std::vector<DataSet> split(DataSet& ds, uint k);

	/**Bootstrap split: sample-with-replacement training set, the unsampled
	 * patterns go to validation.
	 */
	std::pair<DataSet, DataSet> split(DataSet& ds);

	/**Concatenate all DataSet(s) in the vector to one DataSet.
	 * \param splits the DataSet(s) to concatenate.
	 * \return one DataSet consisting of the concatenated DataSet(s).
	 */
	DataSet join(std::vector<DataSet>& splits);

  private:
	/**Build the index vector. This puts all the indices of the DataSet
	 * into a vector in random order.
	 * \param n the number of indices to generate.
	 */
	void buildIndices(uint n);

	/**Build the index vector. This puts all the indices of the DataSet
	 * into a vector in random order. This doesn't check whether we
	 * have already added the generated index. Thus we sample with
	 * replacement. This is meant to be used in conjuction with
	 * bagging.
	 * \param n the number of indices to generate.
	 */
	void buildIndicesWithReplacement(uint n);

	/**Build the index vector. This puts all the indices of the DataSet
	 * into a vector in random order. This doesn't check whether we
	 * have already added the generated index. Thus we sample with
	 * replacement. This is meant to be used in conjuction with
	 * bagging.
	 * \param orig the indices to generate from.
	 */
	void buildIndicesWithReplacement(std::vector<uint>& orig);

	/**Print the built indices.
	 * \param os the output stream to write to.
	 */
	void printIndices(std::ostream& os);

	/**A vector containing an index for every data point in the
	 * original DataSet.
	 */
	std::vector<uint> indices;

	/**Toggle wheather to do the split in a randomised manner or not.
	 * Default is true. When set to false data selection is done
	 * sequentially.
	 */
	bool isRandom;
};
} // namespace DataTools

// ===== datatools/Normaliser.hh =====
#include <vector>

namespace DataTools {
/**A class that can normalise a DataSet using Z-Normalisation.
 * The normalisation is done by calculating the mean and standard
 * deviation of the variables.
 * \f[z=\frac{x-\mu_x}{\sigma_x}\f] where \f$z\f$ is
 * the score, \f$\mu_x\f$ is the mean, and \f$\sigma_x\f$ is the sample
 * standard deviation for the random variable \f$x\f$.
 * \sa DataSet
 */
class Normaliser {
  public:
	/**Basic constructor. */
	Normaliser();

	/**Constructor for fully defining the state of the Normaliser.
	 * \param means the vector of means.
	 * \param stds the vector of standard deviations.
	 * \param skips the vector of variables to skip.
	 */
	Normaliser(std::vector<double>& stds, std::vector<double>& means, std::vector<bool>& skips);

	/**Copy constructor.
	 * \param n the Normaliser to copy from.
	 */
	Normaliser(const Normaliser& n);

	/**Basic destructor. */
	~Normaliser();

	/**Assignment operator.
	 * \param n the Normaliser to assign from.
	 */
	Normaliser& operator=(const Normaliser& n);

	/**Normalise a DataSet. Normalise a DataSet using already
	 * predefined mean ans std vectors.
	 * \param d the DataSet to normalise.
	 * \param doSkip flag whether to do skipping or not.
	 * \return the normalised DataSet.
	 */
	DataSet& normalise(DataSet& d);

	/**Normalise a DataSet. In the normal case every variable in the
	 * DataSet gets normalised. However this method is able to search
	 * through the DataSet to see if any variables are binary and if
	 * so skip rescaling them. Only variables varying between [-1,1]
	 * or [0,1] is skipped. If a variable is determined to be binary
	 * it's mean is set to 0 and it's standard deviation is set to 1
	 * which effectively cancels their rescaling.
	 * \param d the DataSet to normalise.
	 * \param doSkip flag whether to do skipping or not.
	 * \return the normalised DataSet.
	 */
	DataSet& calcAndNormalise(DataSet& d, bool doSkip = false);

	/**Normalise a Pattern.
	 * \param p the Pattern to normalise.
	 * \return the normalised Pattern.
	 */
	Pattern& normalise(Pattern& p);

	/**Normalise an input vector.
	 * \param i the input vector to normalise.
	 * \return the normalized input vector.
	 */
	std::vector<double>& normaliseInput(std::vector<double>& i);

	/**Unnormalise a DataSet.
	 * \param d the DataSet to unnormalise.
	 * \return the unnormalised DataSet.
	 */
	DataSet& unnormalise(DataSet& d);

	/**Unnormalise a Pattern.
	 * \param p the Pattern to unnormalise.
	 * \return the unnormalised Pattern.
	 */
	Pattern& unnormalise(Pattern& p);

	/**Return the standard deviations for the current DataSet.
	 * This is the standard deviations of the DataSet as calculated
	 * before normalisation.
	 * \return the standard deviations of the DataSet.
	 */
	std::vector<double>& stdDev();

	/**Set the standard deviations for the current DataSet.
	 * \param v the standard deviations to set.
	 */
	void stdDev(std::vector<double>& v);

	/**Return the means for the current DataSet.
	 * This is the means of the DataSet as calculated before
	 * normalisation.
	 * \return the means of the DataSet.
	 */
	std::vector<double>& mean();

	/**Set the means for the current DataSet.
	 * \param m the means to set.
	 */
	void mean(std::vector<double>& m);

	/**Return the skips for the current DataSet.
	 * This is the skips of the DataSet as calculated before
	 * normalisation.
	 * \return the skips of the DataSet.
	 */
	std::vector<bool>& skip();

	/**Set the skips for the current DataSet.
	 * \param m the skips to set.
	 */
	void skip(std::vector<bool>& m);

  private:
	/**The standard deviation for each variable in the original
	 * DataSet. This will be used to restore a DataSet to its
	 * original form.
	 */
	std::vector<double> theStdDev;

	/**The mean for each variable in the original DataSet.
	 * This will be used to restore a DataSet to its original form.
	 */
	std::vector<double> theMean;

	/**Contains the indices of the variables to skip in the DataSet.
	 * Thus the values in the columns which index is in theSkip will
	 * not be rescaled.
	 */
	std::vector<bool> theSkip;

	/**Calculate the mean for each variable in the DataSet.
	 * \param d the DataSet.
	 */
	void calcMean(DataSet& d);

	/**Calculate the standard deviation for each variable in the data
	 * set.
	 * \param d the DataSet.
	 */
	void calcStdDev(DataSet& d);

	/**Builds up the skip vector by searching for binary variables. It
	 * only looks for variables using [-1,1] or [0,1] as outputs in
	 * the DataSet.
	 * \param d the DataSet.
	 */
	void findSkip(DataSet& d);

	/**Checks the skip status of a value. This checks if the value is
	 * skipable in the [0,1] case.
	 * \param val the value to check.
	 * \return true if the value indicates skipping and false otherwise.
	 */
	bool skipBin(double val) const;

	/**Checks the skip status of a value. This checks if the value is
	 * skipable in the [-1,1] case.
	 * \param val the value to check.
	 * \return true if the value indicates skipping and false otherwise.
	 */
	bool skipSig(double val) const;

	/**Transform [0,1] binary encoding to [-1,1]. This is useful for
	 * the network learning process. Currently only the inputs are
	 * changed. The target stays at [0,1].
	 * \param data the DataSet to transform.
	 */
	void transformBinaryCoding(DataSet& data);

	/**Transform [0,1] binary encoding to [-1,1]. This is useful for
	 * the network learning process. This method only operates on an
	 * input vector directly.
	 * \param data the DataSet to transform.
	 */
	void transformBinaryCoding(std::vector<double>& input);
};
} // namespace DataTools

// ===== datatools/Sampler.hh =====
#include <memory>
#include <vector>

namespace DataTools {
class Sampler {
  public:
	/**Basic destructor. */
	virtual ~Sampler();

	/**Return the next training/validation sample by value. */
	virtual std::pair<DataSet, DataSet> next() = 0;

	/**Check if there is another sample left.
	 * \return true when there is at least one more sample in the que, false otherwise.
	 */
	virtual bool hasNext() const = 0;

	/**Check how many samples we get in total.
	 * \return the total number of samples we can draw from this Sampler.
	 */
	virtual uint howMany() const = 0;

	/**Accessor for the random sampling attribute.
	 * \return true if random sampling is on, false otherwise.
	 */
	bool randomSampling() const;

	/**Mutator for the random sampling attribute.
	 * \param rs set to true if random sampling is on, false otherwise.
	 */
	void randomSampling(bool rs);

	/**Accessor for the DataSet pointer.
	 * \return the pointer to the DataSet.
	 */
	DataTools::DataSet* data() const;

	/**Mutator for the Data pointer.
	 * \param d the pointer to the Data to set.
	 */
	void data(DataTools::DataSet* d);

	/**Reset the Sampler. This should be called whenever the
	 * attributes has been changed.
	 */
	virtual void reset() = 0;

  protected:
	/**Basic constructor.
	 * \param data the DataSet to sample from.
	 */
	Sampler(DataSet& data);

	/**Copy constructor.
	 * \param eb the Sampler to copy from.
	 */
	Sampler(const Sampler& eb);

	/**Assignment operator.
	 * \param eb the Sampler to assign from.
	 * \return the Sampler assigned to.
	 */
	virtual Sampler& operator=(const Sampler& eb);

	/**Owned DataManager. */
	std::unique_ptr<DataManager> theDataManager;

	/**Pointer to the Data (non-owning). */
	DataSet* theData;

	/**Owned vector of splits. */
	std::unique_ptr<std::vector<DataSet>> theSplits;

  private:
};
} // namespace DataTools

