/**This namespace encloses the MultiLayerPerceptron library.
 * It contains all classes and methods needed to create an MLP.
 */
namespace MultiLayerPerceptron {

/// A define for the Cross Entropy Error identification string.
#define CEE "kullback"
/// A define for the Summed Square Error identification string.
#define SSE "sumsqr"
/// A define for the Quasi Newton minimisation identification string.
#define QN "qn"
/// A define for the Gradient Descent minimisation identification string.
#define GD "gd"
/// A define for the Linear activation function identification string.
#define LINEAR "purelin"
/// A define for the Sigmoid activation function identification string.
#define SIGMOID "logsig"
/// A define for the TanHyp activation function identification string.
#define TANHYP "tansig"
/// A define for the ReLU activation function identification string.
#define RELU "relu"
/// A define for the Leaky ReLU activation function identification string.
#define LEAKYRELU "leakyrelu"
/// A define for the ELU activation function identification string.
#define ELU_ACT "elu"
/// A define for the Adam optimisation identification string.
#define ADAM "adam"
/// A define for the maximum training error.
#define MAX_ERROR 0.00001

/// Normalization type for layers.
enum class NormType : unsigned char { None = 0, BatchNorm = 1, LayerNorm = 2 };

} // namespace MultiLayerPerceptron

// ===== mlp/Layer.hh =====
#include <cassert>
#include <cstdlib>
#include <string>
#include <vector>

namespace MultiLayerPerceptron {
/**A class representing a layer in an Mlp.
 * A Layer has a number of neurons with an activation function held as a
 * std::variant tag (see Activation.hh). The Layer knows the number of
 * neurons contained in itself and its predecessor.
 * \sa Mlp, Activation.
 */
class Layer {
  public:
	/**Constructor from a string activation tag (logsig / tansig / ...). */
	Layer(const uint nc, const uint np, std::string t);

	/**Constructor from an Activation variant directly. */
	Layer(const uint nc, const uint np, Activation act);

	// ACCESSOR AND MUTATOR FUNCTIONS

	/**Index operator: weight at index i. */
	double& operator[](const uint i);

	/**Get the weights leading into this layer.
	 * \return the weight vector.
	 */
	std::vector<double>& weights();
	const std::vector<double>& weights() const;

	/**Set the weights to those in w.
	 * \param w the weights to assign from.
	 */
	void weights(const std::vector<double>& w);

	/**Returns the output from this layer.
	 * Not including the bias!
	 * \return the outputs from this layer.
	 */
	std::vector<double>& outputs();
	const std::vector<double>& outputs() const;

	/**Returns the local gradients in this layer.
	 * \return the local gradients in this layer.
	 */
	std::vector<double>& localGradients();

	/**Return the gradients leading into this layer.
	 * \return the gradients leading into this layer.
	 */
	std::vector<double>& gradients();
	const std::vector<double>& gradients() const;

	/**Return the weight updates leading into this layer.
	 * \return the wight updates leading into this layer.
	 */
	std::vector<double>& weightUpdates();

	// ACCESSOR FUNCTIONS

	double& weights(const uint i, const uint j);
	double& weights(const uint i);
	double& outputs(const uint i);
	double& localGradients(const uint i);
	double& gradients(const uint i, const uint j);
	double& gradients(const uint i);
	double& weightUpdates(const uint i, const uint j);
	double& weightUpdates(const uint i);

	// COUNTS AND CRAP

	uint nWeights() const;
	uint nNeurons() const;
	uint nPrevious() const;
	uint size() const;

	/**The activation tag for this layer (variant over Sigmoid, TanH, ...). */
	const Activation& activation() const { return theAct; }
	Activation& activation() { return theAct; }

	/**The string identifier for this layer's activation (used for serialisation). */
	const std::string& type() const { return theType; }

	// PRINTS

	void printWeights(std::ostream& os) const;
	void printLocalGradients(std::ostream& os) const;
	void printGradients(std::ostream& os) const;

	// UTILS

	/**Weight initialisation scheme.
	 *  - LegacyUniform: U(-0.5, 0.5) for all weights and biases. Pre-Glorot
	 *    behaviour, kept for back-compat with serialised models / older
	 *    benchmarks.
	 *  - Glorot: Glorot/Xavier uniform, U(-a, a) with a = sqrt(6/(n_in+n_out)).
	 *    Biases initialised to zero. Default for new Mlp construction.
	 */
	enum class InitScheme { LegacyUniform, Glorot };

	void initScheme(InitScheme s) { theInitScheme = s; }
	InitScheme initScheme() const { return theInitScheme; }

	/**Assign new random weights to the weight vector. */
	void regenerateWeights();

	// Activation API. Scalar overloads dispatch via std::visit on theAct.
	// fire(uint i) returns the cached output directly (identical across all
	// activations, since outputs[] stores the activation result post-propagate).

	double fire(double lif) const;
	double fire(const uint i) const;
	double firePrime(double lif) const;
	double firePrime(const uint i) const;
	double firePrimePrime(double lif) const;
	double firePrimePrime(const uint i) const;

	/**Propagates an input pattern through this layer.
	 * Note that the bias should not be included in the parameter
	 * since it is explicitly included later.
	 * \param input the input to propagate.
	 * \param preactSkip optional pre-activation skip-add buffer of size
	 *        nNeurons(). Added between the linear+norm step and the
	 *        activation. Pass nullptr (default) for no skip.
	 * \return the outputs from this Layer.
	 */
	std::vector<double>& propagate(const std::vector<double>& input,
	                               const double* preactSkip = nullptr);

	/**Apply the activation derivative to a vector of deltas in batch.
	 * Computes deltas[i] *= f'(outputs[i]) for all neurons.
	 * \param deltas the vector to scale by the derivative.
	 */
	void applyDerivative(std::vector<double>& deltas);

	/**Propagate a batch of inputs through this layer using GEMM. */
	const double* propagateBatch(const double* input, uint B, uint n_in,
	                             const double* preactSkip = nullptr);

	void applyDerivativeBatch(uint B);
	void accumulateGradientsBatch(const double* input, uint B);

	std::vector<double>& batchOutputs();
	std::vector<double>& batchLocalGradients();

	void dropoutRate(double rate);
	double dropoutRate() const;
	void training(bool t);
	bool isTraining() const;

	void normType(NormType nt);
	NormType normType() const;

	std::vector<double>& gamma();
	std::vector<double>& beta();
	std::vector<double>& gammaGradients();
	std::vector<double>& betaGradients();
	std::vector<double>& gammaUpdates();
	std::vector<double>& betaUpdates();

	uint nNormParams() const;

	void applyNormBackwardBatch(uint B);

	std::vector<double> calcLifs(const std::vector<double>& input);

  protected:
	uint index(const uint i, const uint j) const;

	uint ncurr;
	uint nprev;

	/**Type tag (logsig / tansig / ...). Held alongside theAct because
	 * serialisation writes the string and several callers query it. */
	std::string theType;

	/**Activation variant. Replaces the old per-subclass virtual dispatch. */
	Activation theAct;

	std::vector<double> theWeights;
	std::vector<double> theOutputs;
	std::vector<double> theLocalGradients;
	std::vector<double> theGradients;
	std::vector<double> theWeightUpdates;

	double theDropoutRate;
	bool theTraining;
	std::vector<double> theDropoutMask;
	std::vector<double> theBatchDropoutMask;

	std::vector<double> theBatchOutputs;
	std::vector<double> theBatchLocalGradients;

	mutable std::vector<double> theBiasBuf;

	// --- Normalization state ---
	NormType theNormType;
	std::vector<double> theGamma;
	std::vector<double> theBeta;
	std::vector<double> theGammaGrad;
	std::vector<double> theBetaGrad;
	std::vector<double> theGammaUpdate;
	std::vector<double> theBetaUpdate;
	std::vector<double> theRunningMean;
	std::vector<double> theRunningVar;
	double theBNMomentum;
	std::vector<double> theBatchZHat;
	std::vector<double> theBatchNormMean;
	std::vector<double> theBatchNormVar;
	static constexpr double NORM_EPS = 1e-5;

	InitScheme theInitScheme = InitScheme::Glorot;
};

// ACCESSOR AND MUTATOR FUNCTIONS

inline std::vector<double>& Layer::weights() {
	return theWeights;
}

inline const std::vector<double>& Layer::weights() const {
	return theWeights;
}

inline const std::vector<double>& Layer::outputs() const {
	return theOutputs;
}

inline const std::vector<double>& Layer::gradients() const {
	return theGradients;
}

inline void Layer::weights(const std::vector<double>& w) {
	theWeights = w;
}

inline std::vector<double>& Layer::outputs() {
	return theOutputs;
}

inline std::vector<double>& Layer::localGradients() {
	return theLocalGradients;
}

inline std::vector<double>& Layer::gradients() {
	return theGradients;
}

inline std::vector<double>& Layer::weightUpdates() {
	return theWeightUpdates;
}

inline double& Layer::weights(const uint i, const uint j) {
	return theWeights[index(i, j)];
}

inline double& Layer::weights(const uint i) {
	assert(i < theWeights.size());
	return theWeights[i];
}

inline double& Layer::outputs(const uint i) {
	assert(i < theOutputs.size());
	return theOutputs[i];
}

inline double& Layer::localGradients(const uint i) {
	assert(i < theLocalGradients.size());
	return theLocalGradients[i];
}

inline double& Layer::gradients(const uint i, const uint j) {
	return theGradients[index(i, j)];
}

inline double& Layer::gradients(const uint i) {
	assert(i < theGradients.size());
	return theGradients[i];
}

inline double& Layer::weightUpdates(const uint i, const uint j) {
	return theWeightUpdates[index(i, j)];
}

inline double& Layer::weightUpdates(const uint i) {
	assert(i < theWeightUpdates.size());
	return theWeightUpdates[i];
}

// COUNTS AND CRAP

inline uint Layer::nWeights() const {
	return theWeights.size();
}

inline uint Layer::nNeurons() const {
	return ncurr;
}

inline uint Layer::nPrevious() const {
	return nprev;
}

inline uint Layer::size() const {
	return nNeurons();
}

inline std::vector<double>& Layer::batchOutputs() {
	return theBatchOutputs;
}
inline std::vector<double>& Layer::batchLocalGradients() {
	return theBatchLocalGradients;
}
inline void Layer::normType(NormType nt) {
	theNormType = nt;
}
inline NormType Layer::normType() const {
	return theNormType;
}
inline std::vector<double>& Layer::gamma() {
	return theGamma;
}
inline std::vector<double>& Layer::beta() {
	return theBeta;
}
inline std::vector<double>& Layer::gammaGradients() {
	return theGammaGrad;
}
inline std::vector<double>& Layer::betaGradients() {
	return theBetaGrad;
}
inline std::vector<double>& Layer::gammaUpdates() {
	return theGammaUpdate;
}
inline std::vector<double>& Layer::betaUpdates() {
	return theBetaUpdate;
}
inline uint Layer::nNormParams() const {
	return theNormType != NormType::None ? 2 * ncurr : 0;
}
inline void Layer::dropoutRate(double rate) {
	theDropoutRate = rate;
}
inline double Layer::dropoutRate() const {
	return theDropoutRate;
}
inline void Layer::training(bool t) {
	theTraining = t;
}
inline bool Layer::isTraining() const {
	return theTraining;
}

inline double Layer::fire(const uint i) const {
	assert(i < theOutputs.size());
	return theOutputs[i];
}

// PRIVATE--------------------------------------------------------------------//

inline uint Layer::index(const uint i, const uint j) const {
	assert(i < ncurr && j < nprev + 1);
	return i * (nprev + 1) + j;
}

} // namespace MultiLayerPerceptron

// ===== mlp/Mlp.hh =====
namespace MultiLayerPerceptron {
/**A struct representing the model for a multilayer perceptron. */
struct MlpModel {
	std::vector<uint> architecture;
	std::vector<std::string> types;
	bool softmax;
};

/**A Class representing a multilayer perceptron. */
class Mlp {
  public:
	/**Base constructor.
	 * \param a the architecture of this MLP.
	 * \param t the types of neurons that are to be used.
	 * \param s the softmax output switch.
	 */
	Mlp(const std::vector<uint>& a, const std::vector<std::string>& t, bool s);

	/**Base constructor.
	 * \param mlpmodel the model to use for this Mlp.
	 */
	Mlp(const MlpModel& mlpmodel);

	/** Copy constructor.
	 * \param mlp the mlp to copy from.
	 */
	Mlp(const Mlp& mlp);

	/**Move constructor. */
	Mlp(Mlp&& mlp) noexcept = default;

	/**The default destructor.
	 */
	~Mlp();

	/**Assignment operator.
	 * \param mlp the Mlp to assign from.
	 * \return the Mlp assigned to.
	 */
	Mlp& operator=(const Mlp& mlp);

	/**Move assignment operator. */
	Mlp& operator=(Mlp&& mlp) noexcept = default;

	/**Index operator.
	 * \param index the index to return.
	 * \return the layer at position index.
	 */
	Layer& operator[](const uint index);

	// ACCESSORS AND MUTATORS
	/**Return the architechture of this MLP.
	 * \return the architecture.
	 */
	std::vector<uint>& arch();

	/**Return the types of activation functions used in this Mlp.
	 * \return the types.
	 */
	std::vector<std::string>& types();

	/**Return the softmax switch for this Mlp.
	 * \return true if softmax is on, false otherwise.
	 */
	bool softmax();

	/**Enable or disable softmax on the output layer. When enabled,
	 * propagate()/propagateBatch() apply a row-wise softmax to the
	 * last layer's outputs after its activation. Pair with a linear
	 * output layer + cross-entropy for standard multiclass
	 * classification (the (target - output) shortcut in CrossEntropy
	 * gives the correct dL/dz).
	 */
	void softmax(bool s);

	/**Return the number of layers in this MLP.
	 * \return the number of layers.
	 */
	uint numLayers() const;

	/**Returns the indexed layer.
	 * \param index the index to return.
	 * \return the layer at position index.
	 */
	Layer& layer(uint index);

	/**Returns the entire weight vector.
	 * \return the weight vector.
	 */
	std::vector<double> weights() const;

	/**Set the weightvector to the weights in w.
	 * \param w the weights to set the weightvector to.
	 */
	void weights(std::vector<double>& w);

	/**Returns the entire gradient vector.
	 * \return the gradient vector.
	 */
	std::vector<double> gradients() const;

	/**Set the gradient vector to the gradients in g.
	 * \param g the weights to set the gradient vector to.
	 */
	void gradients(std::vector<double>& g);

	// UTILITY
	/**Re-initialise weights using each layer's current init scheme
	 * (Glorot by default; see Layer::InitScheme).
	 */
	void regenerateWeights();

	/**Set the weight init scheme on every layer in this network. Call
	 * before regenerateWeights() to actually take effect.
	 */
	void initScheme(Layer::InitScheme s);

	/**Pushes a pattern through this MLP.
	 * \param pattern the pattern to propagate.
	 * \return the output vector for this pattern.
	 */
	const std::vector<double>& propagate(const std::vector<double>& pattern);

	/**Set training/inference mode for all layers.
	 * \param t true for training, false for inference.
	 */
	void training(bool t);

	/**Set dropout rate for hidden layers (not output layer).
	 * \param rate dropout probability (0 to 1).
	 */
	void dropoutRate(double rate);

	/**Set normalization type for hidden layers (not output layer).
	 * \param nt the normalization type.
	 */
	void normType(NormType nt);

	/**Configure a residual (skip) connection: layer `target`'s output is
	 * element-wise added with layer `source`'s output after activation.
	 *
	 * Requires source < target and matching neuron counts. Pass source = -1
	 * to clear an existing skip on the target layer.
	 */
	void skipFrom(uint target, int source);

	/**Return the skip source for the given target layer, or -1 if none.*/
	int skipFrom(uint target) const;

	/**Propagate a batch of inputs through the entire MLP using GEMM.
	 * \param input pointer to row-major input batch [B x arch[0]].
	 * \param B the batch size.
	 * \return pointer to output batch [B x arch[last]].
	 */
	const double* propagateBatch(const double* input, uint B);

	// SIZE etc
	/**Return the number of layers contained in this MLP.
	 * \return the number of layers.
	 */
	uint nLayers() const;

	/**Return the number of weights contained in this MLP.
	 * \return the number of weights.
	 */
	uint nWeights() const;

	/**Alias for nLayers.
	 * \return the number of layers.
	 */
	uint size() const;

	// PRINTS etc
	/**Print all the weights in the network.
	 * \param os the output stream to write to.
	 */
	void printWeights(std::ostream& os) const;

	/**Print all the gradients in the network.
	 * \param os the output stream to write to.
	 */
	void printGradients(std::ostream& os) const;

  private:
	/**Create all the layers in this MLP.
	 */
	void createLayers();

	/**The architecture for this MLP. */
	std::vector<uint> theArch;

	/**The type of neurons for each layer. */
	std::vector<std::string> theTypes;

	/**Softmax switch. */
	bool theSoftmax;

	/**The layers in this MLP. */
	std::vector<Layer> theLayers;

	/**Skip-connection source per layer; -1 = no skip. */
	std::vector<int> theSkipFrom;
};

// INLINES

inline std::vector<uint>& Mlp::arch() {
	return theArch;
}

inline std::vector<std::string>& Mlp::types() {
	return theTypes;
}

inline bool Mlp::softmax() {
	return theSoftmax;
}

inline void Mlp::softmax(bool s) {
	theSoftmax = s;
}

inline uint Mlp::numLayers() const {
	return theLayers.size();
}
} // namespace MultiLayerPerceptron

// ===== Ensemble.hh =====
#include <memory>
#include <vector>

namespace NeuralNetHack {

/**A class representing an ensemble of Mlp(s). Thus the classification of a
 * pattern is the weighted sum of the classification from each of the Mlp
 * located in this ensemble.
 */
class Ensemble {
  public:
	/**Basic constructor. */
	Ensemble();

	/**Basic constructor. A Ensemble must have at least one MLP.
	 * \param mlp the first mlp in this ensemble.
	 * \param s the scaling of the first MLP.
	 */
	Ensemble(MultiLayerPerceptron::Mlp& mlp, double s);

	/**Copy constructor.
	 * \param c the object to copy from.
	 */
	Ensemble(const Ensemble& c);

	/**Move constructor. */
	Ensemble(Ensemble&&) noexcept = default;

	/**Basic destructor. */
	~Ensemble();

	/**Assignment operator.
	 * \param c the object to assign from.
	 */
	Ensemble& operator=(const Ensemble& c);

	/**Move assignment operator. */
	Ensemble& operator=(Ensemble&&) noexcept = default;

	/**Index operator.
	 * \param i the index of the MLP that is to be returned.
	 * \return the MLP located at index i.
	 */
	MultiLayerPerceptron::Mlp& operator[](const uint i);

	/**Fetch one of the MLPs in the committee.
	 * \param i the index of the MLP that is to be returned.
	 * \return the MLP located at index i.
	 */
	MultiLayerPerceptron::Mlp& mlp(const uint i);

	/**Fetch one of the MLPs in the committee (const).
	 * \param i the index of the MLP that is to be returned.
	 * \return the MLP located at index i.
	 */
	const MultiLayerPerceptron::Mlp& mlp(const uint i) const;

	/**Delete and fetch one of the MLPs in the committee.
	 * \param i the index of the MLP that is to be deleted.
	 */
	void delMlp(const uint i);

	/**Add an MLP to this ensemble. This will copy the mlp.
	 * \param mlp the MLP to add.
	 * \param s the scale for this MLP.
	 */
	void addMlp(MultiLayerPerceptron::Mlp& mlp, double s);

	/**Add an MLP to this ensemble. This will copy the mlp.
	 * The scale for each MLP in the Committe is set to 1/N.
	 * Thus all previous scales are destroyed.
	 * \param mlp the MLP to add.
	 */
	void addMlp(MultiLayerPerceptron::Mlp& mlp);

	/**Add an MLP to this ensemble by taking ownership.
	 * \param mlp the MLP to add (ownership transferred).
	 * \param s the scale for this MLP.
	 */
	void addMlp(std::unique_ptr<MultiLayerPerceptron::Mlp> mlp, double s);

	/**Add an MLP to this ensemble by taking ownership.
	 * The scale for each MLP in the Committe is set to 1/N.
	 * Thus all previous scales are destroyed.
	 * \param mlp the MLP to add (ownership transferred).
	 */
	void addMlp(std::unique_ptr<MultiLayerPerceptron::Mlp> mlp);

	/**Return the scale for the MLP located at index i.
	 * \param i the index of the MLP which scale is to be returned.
	 */
	double scale(const uint i) const;

	/**Set the scale for the MLP located at index i.
	 * \param i the index of the MLP which scale is to be returned.
	 * \param s the scale to set.
	 */
	void scale(const uint i, double s);

	/**Return the number of MLPs residing in this ensemble. */
	uint size() const;

	/**Propagate the input through this ensemble of MLPs.
	 * The input is propagated through each of the MLPs. Their
	 * respective output is then combined linearly with their
	 * respective scaling to produce the output for this Ensemble.
	 * \param input the input to propagate.
	 */
	std::vector<double> propagate(const std::vector<double>& input);

  private:
	/**A committee of MLPs. */
	std::vector<std::unique_ptr<MultiLayerPerceptron::Mlp>> theEnsemble;

	/**The scales(weights) to use when combining the output from each
	 * MLP. By default the standard mean value is computed.
	 * \f[y_c=\sum_i\alpha_i y_i\f]
	 */
	std::vector<double> theScales;
};
} // namespace NeuralNetHack

// ===== FeatureSelector.hh =====
#include <ostream>


namespace NeuralNetHack {
class FeatureSelector {
  public:
	/**Basic constructor for the FeatureSelector class.
	 * \param minf the minimum number of features to keep
	 * \param maxf the maximum number of features to keep
	 * \param maxf the maximum number of features to remove in each iteration
	 */
	FeatureSelector(uint minf, uint maxf, uint maxr);

	/**Runs the feature selction process.
	 * \param config the Config object to read configuration from
	 * \param f the evaluator function for assessing the quality of a feature set
	 * \return the new Config object with the reduced feature set.
	 */
	Config run(Config& config, double (*f)(Ensemble&, DataTools::DataSet&));

  private:
	/**Parses the data files given in config using the input columns
	 * given in config.
	 * \param config the Config to use.
	 * \param trnData the training DataSet to fill up.
	 * \param tstData the test DataSet to fill.
	 */
	void parseData(Config& config, DataTools::DataSet& trnData, DataTools::DataSet& tstData);

	/**Selects the features to remove based on the given values in effects.
	 * \param effects the effects removing a feature had on the performance measure.
	 */
	std::vector<uint> removeFeatures(std::vector<double>& effects, const std::vector<uint>& inputs);

	void storeClampingEffect(Ensemble& e, DataTools::DataSet& d, double auc,
	                         std::vector<double>& aucImpact,
	                         double (*f)(Ensemble&, DataTools::DataSet&));

	/**Calculates the mean value for a specific variable in the given DataSet.
	 * \param d the DataSet to find the variable in.
	 * \param index the index of the variable to calculate the mean for.
	 * \return the mean for the variable with the given index.
	 */
	double mean(DataTools::DataSet& d, uint index);

	/** The minimum number of features to keep in the model. */
	uint minFeatures;
	/** The maximum number of features to keep in the model. */
	uint maxFeatures;
	/** The maximum number of features to remove in each iteration from the model. */
	uint maxRemove;
	/** The best Config setting so far. */
	Config best;
};
} // namespace NeuralNetHack

// ===== OddsRatio.hh =====
#include <vector>
#include <ostream>
#include <functional>

namespace NeuralNetHack {
/**This namespace encloses functions for calculating effective odds
 * ratios. It is currently limited to single output networks using a
 * sigmoidal activation function in the output layer. We define the Odds
 * for an input to be
 * \f[Odds = \frac{y^{present}}{1-y^{present}}\f]
 * where \f$y^{present}\f$ is the output from the Mlp given that the input
 * is present. Thus, the odds ratio is defined as
 * \f[OR = \frac{ y^{present}(1-y^{absent}) }{ y^{absent}(1-y^{present}) }\f]
 */
namespace OddsRatio {

/**Calculates the odds ratios for each data point and mlp and return the
 * average. This performs an extra sum where we simply take the
 * average over Mlp:s and data points.
 * \f[\sum_c^C\sum_n^N \overline{OR_n}\f] where \f$N\f$ is the total number
 * of data points, and \f$C\f$ is the total number of ensemble members.
 * \param mlp the Mlp to use.
 * \param pattern the DataSet to calculate OR:s for each data point on.
 * \return the average OR for each Mlp and input in the DataSet.
 */
std::vector<double> oddsRatio(Ensemble& ensemble, DataTools::DataSet& data);

/**Calculates the odds ratios for each variable in the pattern.
 * This performs an extra sum where we simply take the
 * average over Mlp:s. \f[\sum_c^C \overline{OR_c}\f] where \f$C\f$
 * is the total number of ensemble members.
 * \param mlp the Mlp to use.
 * \param pattern the DataSet to calculate OR:s for each data point on.
 * \return the average OR for each Mlp and input in the DataSet.
 */
std::vector<double> oddsRatio(Ensemble& ensemble, DataTools::Pattern& pattern);

/**Print the result of an OddsRatio calculation for all Inputs in the
 * DataSet.
 * \param os the output stream to write to.
 * \param oddsrat the oddsratios to write.
 */
void print(std::ostream& os, std::vector<double>& oddsrat);

} // namespace OddsRatio
} // namespace NeuralNetHack

// ===== Saliency.hh =====
#include <vector>
#include <ostream>

namespace NeuralNetHack {
/**This namespace encloses functions for calculating salinecies for a
 * given datapoint for a given Mlp or Ensemble.
 */
namespace Saliency {

/**Propagates an input through an Mlp up to the last layer. This seems
 * very similar to the propagate function in the mlp, but they differ
 * in that this propagate does not activate the last layer, but thus
 * only calculates the induced local field.
 * \param mlp the mlp to propagate the input through.
 * \param input the input to propagate.
 * \return the local induced field for the output neuron.
 */
double propagate(MultiLayerPerceptron::Mlp& mlp, std::vector<double>& input);

/**Calculate the magnitude of the saliency for each variable averaged over all
 * datapoints and committee members. This means that we don't use the
 * sign of the derivative in the calculation. We only want to measure
 * importance for the output. This is used in feature selection.
 * \param committee the committee to use as a predictor
 * \param data the data set containing all variables
 * \return a vector of averaged variable saliences
 */
std::vector<double> saliencyMagnitude(Ensemble& committee, DataTools::DataSet& data, bool inner);

/**Calculate the saliency for each variable averaged over all
 * datapoints and committee members.
 * \param committee the committee to use as a predictor
 * \param data the data set containing all variables
 * \return a vector of averaged variable saliences
 */
std::vector<double> saliency(Ensemble& committee, DataTools::DataSet& data, bool inner);

/**Calculate the saliency for each variable in the pattern averaged over all
 * committee members.
 * \param committee the committee to use as a predictor
 * \param pattern the pattern containing all variables
 * \return a vector of averaged variable saliences
 */
std::vector<double> saliency(Ensemble& committee, DataTools::Pattern& pattern, bool inner);

/**Calculate the magnitude of the saliency for each variable averaged over all
 * datapoints. This means that we don't use the
 * sign of the derivative in the calculation. We only want to measure
 * importance for the output. This is used in feature selection.
 * \param committee the committee to use as a predictor
 * \param data the data set containing all variables
 * \return a vector of averaged variable saliences
 */
std::vector<double> saliencyMagnitude(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& data,
                                      bool inner);

/**Calculate the saliency for each variable averaged over all
 * datapoints.
 * \param mlp the mlp to use as a predictor
 * \param data the data set containing all variables
 * \return a vector of averaged variable saliences
 */
std::vector<double> saliency(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& data, bool inner);

/**Calculate the saliency for each variables in the pattern.
 * \param mlp the mlp to use as a predictor
 * \param pattern the pattern containing all variables
 * \return a vector of variable saliences
 */
std::vector<double> saliency(MultiLayerPerceptron::Mlp& mlp, DataTools::Pattern& pattern,
                             bool inner);

/**Calculate the partial derivative of the output with respect to an
 * input variable.
 * \param mlp the mlp to use as a predictor
 * \param input the input vector containing all variables
 * \param index the index of the varible to use for the partial derivative
 * \return the value of the partial derivative
 */
double derivative(MultiLayerPerceptron::Mlp& mlp, std::vector<double>& input, uint index);

/**Calculate the partial derivative of the output with respect to an
 * input variable. This function is restricted to two Layer Mlp:s and
 * has been used for debugging purposes.
 * \param mlp the mlp to use as a predictor
 * \param input the input vector containing all variables
 * \param index the index of the varible to use for the partial derivative
 * \return the value of the partial derivative
 */
double derivative_debug(MultiLayerPerceptron::Mlp& mlp, std::vector<double>& input, uint index);

/**Calculate the partial derivative of the output with respect to an
 * input variable. Note that the last activation function is not used
 * in this derivative. Thus what we use is the linear combination of
 * the activation of each hidden node plus a bias.
 * \param mlp the mlp to use as a predictor
 * \param input the input vector containing all variables
 * \param index the index of the varible to use for the partial derivative
 * \return the value of the partial derivative
 */
double derivative_inner(MultiLayerPerceptron::Mlp& mlp, std::vector<double>& input, uint index);

/**Print the result of an Saliency calculation for all Inputs in the
 * DataSet.
 * \param os the output stream to write to.
 * \param saliency the saliencies to write.
 */
void print(std::ostream& os, std::vector<double>& saliency);
} // namespace Saliency
} // namespace NeuralNetHack

// ===== evaltools/Conformal.hh =====
#include <vector>

namespace EvalTools {

/**Split conformal prediction on top of a NeuralNetHack::Ensemble.
 *
 * Two modes:
 *   - Regression: per-dim residual score \f$|t_d - \hat y_d|\f$. Each
 *     output dim gets its own quantile \f$\hat q_d\f$. Marginal coverage
 *     \f$1-\alpha\f$ per dim under exchangeability.
 *   - Classification (LAC, "least ambiguous classifier"): non-conformity
 *     score \f$1 - \hat p_{y}\f$ where \f$y\f$ is the true class. Single
 *     \f$\hat q\f$. Prediction set \f$\{k : \hat p_k \ge 1 - \hat q\}\f$.
 *     Marginal coverage \f$1-\alpha\f$.
 *
 * Caller owns the train/calibration split; pass the held-out calibration
 * DataSet to calibrate(). Use DataTools::HoldOutSampler if you want the
 * standard random split.
 *
 * Classification handles both single-output (sigmoid, treated as 2-class
 * with probs \f$[1-y, y]\f$) and multi-output softmax (one-hot target).
 */
class Conformal {
  public:
	enum class Mode { Regression, Classification };

	struct Interval {
		double lo;
		double hi;
	};

	/**Construct an uncalibrated conformal predictor.
	 * \param mode regression or classification.
	 * \param alpha miscoverage rate in (0,1). 0.1 → 90% target coverage.
	 */
	Conformal(Mode mode, double alpha);

	/**Compute non-conformity scores on the calibration set and store the
	 * \f$1-\alpha\f$ finite-sample-corrected quantile. Must be called
	 * before any predict / coverage call. Sets the output dimension from
	 * the ensemble's first prediction.
	 */
	void calibrate(NeuralNetHack::Ensemble& e, DataTools::DataSet& cal);

	/**Regression: per-dim conformal interval around the ensemble mean
	 * prediction, length nOutput. Throws on mode mismatch or if not
	 * calibrated.
	 */
	std::vector<Interval> interval(NeuralNetHack::Ensemble& e, const std::vector<double>& x) const;

	/**Classification: prediction set as sorted class indices. Throws on
	 * mode mismatch or if not calibrated. May be empty in pathological
	 * cases (model is overconfident on every wrong class for this point).
	 */
	std::vector<uint> set(NeuralNetHack::Ensemble& e, const std::vector<double>& x) const;

	/**Marginal empirical coverage on a held-out test DataSet.
	 * Regression: fraction over (pattern, dim) pairs.
	 * Classification: fraction of patterns whose true class is in the set.
	 * Sanity check; returns NaN on empty input.
	 */
	double coverage(NeuralNetHack::Ensemble& e, DataTools::DataSet& tst) const;

	/**Per-dim regression quantiles (length nOutput) or single-element
	 * vector with the LAC quantile. Empty before calibrate().
	 */
	const std::vector<double>& quantiles() const { return theQ; }

	Mode mode() const { return theMode; }
	double alpha() const { return theAlpha; }
	bool calibrated() const { return theCalibrated; }

  private:
	Mode theMode;
	double theAlpha;
	uint theNOutput = 0;
	std::vector<double> theQ;
	bool theCalibrated = false;
};

} // namespace EvalTools

// ===== evaltools/ConfusionMatrix.hh =====
#include <ostream>
#include <vector>

namespace EvalTools {

/**A confusion matrix indexed as `m(actual, predicted)`.
 *
 * Works for binary and multi-class problems. For binary, the convention is
 * class 0 = negative, class 1 = positive (matching the existing Evaluator).
 * Build one from raw vectors or directly from an Ensemble.
 */
class ConfusionMatrix {
  public:
	explicit ConfusionMatrix(uint nClasses);

	void add(uint actual, uint predicted);
	void reset();

	uint nClasses() const { return n; }
	uint count(uint actual, uint predicted) const { return m[actual][predicted]; }
	uint total() const;
	uint correct() const;                // diagonal sum
	uint actualTotal(uint cls) const;    // row sum
	uint predictedTotal(uint cls) const; // column sum

	// Binary convenience (asserts nClasses() == 2).
	uint tp() const;
	uint fp() const;
	uint fn() const;
	uint tn() const;

	void print(std::ostream& os) const;

	// ---- Builders ----

	/**Threshold predictions at `cut` (default 0.5) and tally a 2x2 matrix.
	 * `output` is the model's probability for class 1 per pattern.
	 */
	static ConfusionMatrix fromBinary(const std::vector<double>& output,
	                                  const std::vector<uint>& target, double cut = 0.5);

	/**Argmax both predictions and one-hot targets to tally an NxN matrix.
	 * `output[i]` and `target[i]` must each have length == nClasses.
	 */
	static ConfusionMatrix fromMulticlass(const std::vector<std::vector<double>>& output,
	                                      const std::vector<std::vector<double>>& target);

	/**Build directly from an Ensemble + DataSet. Auto-detects binary vs
	 * multi-class from the first prediction's output dimension. For the
	 * binary case, classifies at `cut`.
	 */
	static ConfusionMatrix fromEnsemble(NeuralNetHack::Ensemble& committee,
	                                    DataTools::DataSet& data, double cut = 0.5);

  private:
	uint n;
	std::vector<std::vector<uint>> m; // m[actual][predicted]
};

} // namespace EvalTools

// ===== evaltools/EvalTools.hh =====
#include <vector>

/**This namespace encloses a bunch of functions needed to
 * evaluate the performance of a classifier or a regressor.
 *
 * Classification metrics: crossEntropy, auc, gof, plus ConfusionMatrix-derived
 * accuracy, precision, recall, f1, mcc, balancedAccuracy, and macro variants.
 * Regression metrics: mae, mape, smape, rmse, r2.
 * Generic: summedSquare.
 */
namespace EvalTools {
namespace ErrorMeasures {
/**Measures the CrossEntropyError for an entire DataSet.
 * This is also known as the kullback leibler error measure.
 * This measure is intended to be used with classification
 * problems for two class single output problems. In the
 * special case of one output and two classes the following will be used:
 * \f[E=-\frac{1}{N}\sum_{n}\left(d_n\ln y_n + (1-d_n)\ln (1-y_n)\right)\f]
 * Otherwise we use:
 * \f[E=-\frac{1}{N}\sum_{n}\sum_{i}\left(d_i\ln\left(\frac{y_i}{d_i}\right)\right)\f]
 * \param committee the ensemble of Mlp to estimate the error for.
 * \param data the DataSet to use for error measure.
 * \return the cross entropy error.
 */
double crossEntropy(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Measures the CrossEntropyError for one data point.
 * This is also known as the kullback leibler error measure.
 * This measure is intended to be used with classification
 * problems for two class single output problems. In the
 * special case of one output and two classes the following will be used:
 * \f[E=-\frac{1}{N}\sum_{n}\left(d_n\ln y_n + (1-d_n)\ln (1-y_n)\right)\f]
 * Otherwise we use:
 * \f[E=-\frac{1}{N}\sum_{n}\sum_{i}\left(d_i\ln\left(\frac{y_i}{d_i}\right)\right)\f]
 * \param output the output vector of the classifier.
 * \param target the target.
 * \return the cross entropy error.
 */
double crossEntropy(const std::vector<double>& output, const std::vector<double>& target);

/**Measures the SummedSquareError for an entire DataSet.
 * \f[E=\frac{1}{2N}\sum_{n}\sum_{i}(d_i-y_i)^2\f]
 * \param committee the ensemble of Mlp to estimate the error for.
 * \param data the DataSet to use for error measure.
 * \return the summed square error.
 */
double summedSquare(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Measures the SummedSquareError for an entire DataSet.
 * \f[E=\frac{1}{2N}\sum_{n}\sum_{i}(d_i-y_i)^2\f]
 * \param output the output vector of the classifier.
 * \param target the target.
 * \return the summed square error.
 */
double summedSquare(const std::vector<double>& output, const std::vector<double>& target);

/**Measures the AUC(Area Under Curve) for the ROC(Receicer Operating
 * Characteristics).
 * \param committee the ensemble of Mlp to estimate the error for.
 * \param data the DataSet to use for error measure.
 * \return the area under curve.
 */
double auc(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Classification accuracy: fraction of patterns whose predicted class
 * matches the target. Single-output is binary (threshold 0.5);
 * multi-output is multiclass via argmax over both vectors. Use this
 * instead of auc() when the architecture has more than one output.
 * \param committee the ensemble of Mlp to estimate the error for.
 * \param data the DataSet to use for error measure.
 * \return accuracy in [0, 1].
 */
double accuracy(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Measures the Hosmer Lemeshow goodness of fit statistics.
 * \f[\chi ^2 = \sum_{j=1}^{G}\frac{(o_j - n_j \bar{\pi}_j)^2}{ n_j \bar{\pi}_j (1 - \bar{\pi}_j)
 * }\f] Where \f$o_j\f$ is the number of observed positives in bin j, and
 * \f$\bar{\pi}_j\f$ is the mean average predicted value in bin j. G is
 * the number of bins meanwhile \f$n_j\f$ is the number of samples in the
 * bin.This test statistics follow the chi square statistics with a (G-2)
 * deegree of freedom.
 * \param committee the ensemble of Mlp to estimate the error for.
 * \param data the DataSet to use for error measure.
 * \return the hosmer lemeshow statistics.
 */
double gof(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

void buildOutputTargetVectors(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data,
                              std::vector<double>& output, std::vector<uint>& target);

void buildOutputTargetVectors(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data,
                              std::vector<std::vector<double>>& output,
                              std::vector<std::vector<double>>& target);

/**Flatten a DataSet of multi-output predictions and targets into a single
 * pair of vectors, concatenated pattern by pattern. Used by the regression
 * metrics below.
 */
void buildFlatRegressionVectors(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data,
                                std::vector<double>& output, std::vector<double>& target);

// ---- Regression metrics --------------------------------------------------
//
// All take "flat" vectors: predictions and actuals concatenated across the
// whole dataset. Use buildFlatRegressionVectors (or the Ensemble overloads
// below) when you have a model + DataSet.

/**Mean absolute error: \f$\frac{1}{N}\sum_i |t_i - y_i|\f$.*/
double mae(const std::vector<double>& output, const std::vector<double>& target);
double mae(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Mean absolute percentage error in percent:
 * \f$\frac{100}{N}\sum_i |t_i - y_i| / |t_i|\f$.
 *
 * Elements with \f$|t_i|\f$ below a small epsilon are skipped (MAPE is
 * undefined at zero). Returns NaN if every element is skipped.
 */
double mape(const std::vector<double>& output, const std::vector<double>& target);
double mape(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Symmetric MAPE in percent:
 * \f$\frac{200}{N}\sum_i |t_i - y_i| / (|t_i| + |y_i|)\f$.
 *
 * Bounded between 0 and 200. Better behaved than MAPE near zero, since the
 * denominator only vanishes when both target and prediction are zero (in
 * which case that element is skipped).
 */
double smape(const std::vector<double>& output, const std::vector<double>& target);
double smape(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Root mean squared error: \f$\sqrt{\frac{1}{N}\sum_i (t_i - y_i)^2}\f$.*/
double rmse(const std::vector<double>& output, const std::vector<double>& target);
double rmse(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

/**Coefficient of determination:
 * \f$R^2 = 1 - \frac{\sum_i (t_i - y_i)^2}{\sum_i (t_i - \bar t)^2}\f$.
 *
 * Returns 1 for a perfect fit, 0 for a model that's no better than
 * predicting the target mean, and can go negative for a worse-than-mean
 * model. Returns NaN if the targets are constant (denominator is zero).
 */
double r2(const std::vector<double>& output, const std::vector<double>& target);
double r2(NeuralNetHack::Ensemble& committee, DataTools::DataSet& data);

// ---- Confusion-matrix derived metrics -----------------------------------
//
// Build a ConfusionMatrix (binary, multi-class, or via fromEnsemble) and
// pass it to any of these. Per-class metrics default to class 1 (the
// positive class in the binary convention).

/**Overall accuracy: correct / total. Returns NaN if the matrix is empty.*/
double accuracy(const ConfusionMatrix& cm);

/**Precision for class `cls`: TP_cls / (TP_cls + FP_cls).
 * Returns NaN if no instance was predicted as `cls`.
 */
double precision(const ConfusionMatrix& cm, uint cls = 1);

/**Recall (sensitivity) for class `cls`: TP_cls / (TP_cls + FN_cls).
 * Returns NaN if `cls` never appears in the ground truth.
 */
double recall(const ConfusionMatrix& cm, uint cls = 1);

/**F1 score for class `cls`: harmonic mean of precision and recall.
 * Returns NaN if either input is undefined or both are zero.
 */
double f1(const ConfusionMatrix& cm, uint cls = 1);

/**Matthews correlation coefficient for binary classification.
 * Range -1 (anti-correlated) to +1 (perfect). Returns NaN for non-binary
 * matrices or when the denominator is zero.
 */
double mcc(const ConfusionMatrix& cm);

/**Mean recall across classes. Robust to class imbalance.*/
double balancedAccuracy(const ConfusionMatrix& cm);

/**Unweighted mean of per-class precision / recall / F1 across all classes.
 * Classes whose individual metric is NaN are skipped from the mean.
 */
double macroPrecision(const ConfusionMatrix& cm);
double macroRecall(const ConfusionMatrix& cm);
double macroF1(const ConfusionMatrix& cm);
} // namespace ErrorMeasures
} // namespace EvalTools

// ===== evaltools/Evaluator.hh =====
#include <vector>
#include <ostream>

#define NEG 0
#define POS 1

namespace EvalTools {

/**A class used to evaluate output from a classifier.
 * The classifier is evaluated using sensitivity(TPF) and specificity(TNF).
 * Currently it is limited to only two classes using local encoding.
 * Distributed encoding is not supported in this class.
 * \f[TPF=\frac{Number~of~true~positive~decisions}
 * {Number~of~actually~positive~cases}\f]
 * \f[TNF=\frac{Number~of~true~negative~decisions}
 * {Number~of~actually~negative~cases}\f]
 * Also we have the following equivalences:
 * \f[TPF+FNF=1\f] and \f[TNF+FPF=1\f]
 */
class Evaluator {
  public:
	/**Basic constructor. */
	Evaluator();

	/**Copy constructor.
	 * \param eval the object to copy.
	 */
	Evaluator(const Evaluator& eval);

	/**Basic destructor.*/
	virtual ~Evaluator();

	/**Assigment operator.
	 * \param eval the object to copy.
	 */
	Evaluator& operator=(const Evaluator& eval);

	/**Return the True Positive Fraction for the evaluation.
	 * i.e. the sensitivity.
	 */
	double tpf();

	/**Return the False Negative Fraction for the evaluation. */
	double fnf();

	/**Return the True Negative Fraction for the evaluation.
	 * i.e. the specificity.
	 */
	double tnf();

	/**Return the False Positive Fraction for the evaluation.*/
	double fpf();

	/**Return the cut used for the evaluation.*/
	double cut();

	/**Set the cut used for the evaluation.
	 * \param c the cut to set.
	 */
	void cut(double c);

	/**Calculate the number of TP and TN for a classifier.
	 * \param out the output from the classifier.
	 * \param dout the target output for the data points.
	 */
	void evaluate(std::vector<double>& out, std::vector<uint>& dout);

	/**Print the sensitivity and specificity.
	 * \param os the stream to output to.
	 */
	void print(std::ostream& os);

  private:
	/**Put all counters to zero.
	 * In effect all attributes are set to 0.
	 */
	void reset();

	/**Classify each output as POS or NEG depending on the cut.
	 * This uses theCut variable to decide whether the output should
	 * be regarded as POS or NEG.
	 * \param out the output to be classified.
	 * \return the classified outputs.
	 */
	std::vector<uint> cutOutput(std::vector<double>& out);

	/**Convert a vector of doubles to a vector of uints.
	 * \param vec the double vector.
	 * \return the converted vector.
	 */
	std::vector<uint> vectorDoubleToUint(std::vector<double>& vec);

	/**Calculate the Sensitivity and Specificity for the classifier.
	 * This uses the TruePos and TrueNeg variables to do this.
	 */
	void calcRates();

	/**The True Positive Fraction for the current evaluation.
	 * In other words the specificity.
	 */
	double theTnf;

	/**The True Positive Fraction for the current evaluation.
	 * In other words the sensitivity.
	 */
	double theTpf;

	/**The cut assigning the classifier output to 1 or 0.
	 * This cut decides wheather the classifier output should be classified
	 * as POS or NEG.
	 */
	double theCut;

	/**The number of true positives.*/
	uint nTp;

	/**The number of true negatives.*/
	uint nTn;

	/**The number of positive samples in the data. */
	uint nP;

	/**The number of negative samples in the data. */
	uint nN;
};
} // namespace EvalTools

// ===== evaltools/Roc.hh =====
#include <memory>
#include <vector>
#include <utility>
#include <ostream>

namespace EvalTools {

class Evaluator;

/**A class representing the creation and evaluation of an ROC.
 * The ROC consists of FPF(1-specificity) plotted against TPF(sensitivity)
 * This class only accepts data sets that have a single output featuring
 * two classes. It can calculate the AUC(Area Under Curve) from the ROC in
 * two ways. (i) Using Trapezoidal rule on the generated FPF,TPF data points.
 * (ii) Using Wilcoxon-Mann-Whitney rank statistics.
 * \todo Both wmw methods are sensitive to ties i.e. when an output from
 * the negative class is equal to an output from the positive class. The
 * problem is how to rank them since they give different rank if permuted.
 * The normal wmw tries to compensate a bit using 0.5 when an output from
 * negative class has the same value as one from the positive class.
 */
class Roc {

  public:
	/**Basic constructor. */
	Roc();

	/**Copy constructor.
	 * \param roc the object to copy from.
	 */
	Roc(const Roc& roc);

	/**Basic destructor. */
	virtual ~Roc();

	/**Assignment operator.
	 * \param roc the object to assign from.
	 * \return the object assigned to.
	 */
	Roc& operator=(const Roc& roc);

	/**Fetch the ROC in pairs of FPF and TPF.
	 * \return the ROC.
	 */
	std::vector<std::pair<double, double>>& roc();

	/**Return the area under the ROC curve.
	 * \return the AUC for the ROC curve.
	 */
	double auc();

	/**Estimate the AUC using the Wilcoxon-Mann-Whitney rank
	 * statistics. This is exactely the AUC when no ties are present.
	 * This compares all pairs in the positive output list and the
	 * negative output list.
	 * \f[AUC=\frac{\sum_{i=0}^{m-1}\sum_{j=0}^{n-1}I(x_i, y_j)}{m\cdot n}\f]
	 * \f[I(x_i, y_j)=\left\{\begin{array}{cc}
	 * 1, & x_i>y_j\\
	 * 0, & otherwise
	 * \end{array}\right.\f]
	 * \todo Make this less sensitive to ties.
	 * \param out the data.
	 * \param dout the target data.
	 * \return the AUC.
	 */
	double calcAucWmw(std::vector<double>& out, std::vector<uint>& dout);

	/**Estimate the AUC using the Wilcoxon-Mann-Whitney rank
	 * statistics. This is exactely the AUC when no ties are present.
	 * This is another way of calculating the WMW statistics using the
	 * wilcoxon rank sum.
	 * \f[AUC=\frac{1}{m\cdot
	 * n}\left(\sum_{i=0}^{m-1}r_i-\frac{m(m-1)}{2}\right)\f]
	 * where \f$m\f$ is the number of positive samples and
	 * \f$n\f$ is the number of negative samples in the data set. \f$r_i\f$ is
	 * the rank for the outputs generated from the positive sample set.
	 * \todo Make this less sensitive to ties.
	 * \param out the data.
	 * \param dout the target data.
	 * \return the AUC.
	 */
	double calcAucWmwFast(std::vector<double>& out, std::vector<uint>& dout);

	/**Estimate the AUC using the trapezoidal rule. This
	 * is a brute force way of integrating the area under the ROC plot.
	 * \f[AUC=\sum_{i=1}^{n-1}(x_i-x_{i-1})\cdot 0.5\cdot(y_i+y_{i-1})\f] where
	 * \f$n\f$ is the number of data points.
	 * \param out the data.
	 * \param dout the target data.
	 * \return the AUC.
	 */
	double calcAucTrapezoidal(std::vector<double>& out, std::vector<uint>& dout);

	/**Create a FPF,TPF pair for each value in out.
	 * This basically generate a (1-specificity), sensitivity
	 * pair for each output.
	 * \param out the output to evaluate, which also serves as the
	 * cuts.
	 * \param dout the target output.
	 */
	void calcRoc(std::vector<double>& out, std::vector<uint>& dout);

	/**Print the ROC data to stdout.
	 * \param os the stream to output to.
	 */
	void print(std::ostream& os);

  private:
	/**The FPF and TPF for each cut. The first double is the FPF
	 * and the second is the TPF.
	 */
	std::vector<std::pair<double, double>> theRoc;

	template <class T> void printVector(std::vector<T>& vec);

	/**The area under the ROC curve. */
	double theAuc;

	/**The evaluator. */
	std::unique_ptr<Evaluator> theEval;
};

// INLINES

inline double Roc::auc() {
	return theAuc;
}
inline std::vector<std::pair<double, double>>& Roc::roc() {
	return theRoc;
}

} // namespace EvalTools

// ===== mlp/Error.hh =====
#include <memory>
#include <vector>

namespace MultiLayerPerceptron {
/**A base class representing the error functions. The error function is
 * responsible for calculating an error and a gradient to update the Mlp
 * weights by. Also every Error function use full batch mode i.e. it is up
 * to the Trainer to divide it into block or online by dividing the
 * DataSet that it receives into sub DataSet:s. The impementation specific
 * Error function \f[E\f] is extended with
 * \f[\hat{E} = E + \nu\sum_i\frac{\omega_i^2}{\omega_0^2 + \omega_i^2}\f]
 * \sa SummedSquare, CrossEntropy, DataSet, Trainer.
 */
class Error {
  public:
	/**Basic destructor. */
	virtual ~Error();

	/**Calculate the gradient vector, and return the error.
	 * This returns the error calculated from a block of patterns.
	 * \param mlp the MLP to calculate the gradient for.
	 * \param dset the data set to use.
	 * \return the error.
	 */
	virtual double gradient(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& dset) = 0;

	/**Calculate the gradient vector, and return the error.
	 * This returns the error calculated from a block of patterns.
	 * \return the error.
	 */
	virtual double gradient() = 0;

	/**Calculate the summed square error for this Mlp and DataSet.
	 * \param mlp the output from the MLP.
	 * \param dset the desired output.
	 * \return the error.
	 */
	virtual double outputError(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& dset) = 0;

	/**Calculate the error for this Mlp and DataSet.
	 * \return the error.
	 */
	virtual double outputError() const = 0;

	/**Accessor method for the Mlp.
	 * \return the Mlp belonging to the Error.
	 */
	MultiLayerPerceptron::Mlp& mlp();

	/**Mutator method for the Mlp.
	 * \param mlp the Mlp to assign to this Error.
	 */
	void mlp(MultiLayerPerceptron::Mlp& mlp);

	/**Accessor method for the DataSet.
	 * \return the DataSet belonging to the Error.
	 */
	DataTools::DataSet& dset();

	/**Mutator method for the DataSet.
	 * \param dset the DataSet to assign to this Error.
	 */
	void dset(DataTools::DataSet& dset);

	/**Accessor for theWeightElimOn.
	 * \return the theWeightElimOn.
	 */
	bool weightElimOn() const;

	/**Mutator for theWeightElimOn.
	 * \param on the value to set.
	 */
	void weightElimOn(bool on);

	/**Accessor for theWeightElimAlpha.
	 * \return the theWeightElimAlpha.
	 */
	double weightElimAlpha() const;

	/**Mutator for theWeightElimAlpha.
	 * \param alpha the value to set.
	 */
	void weightElimAlpha(double alpha);

	/**Accessor for theWeightElimW0.
	 * \return the theWeightElimW0.
	 */
	double weightElimW0() const;

	/**Mutator for theWeightElimW0.
	 * \param w0 the value to set.
	 */
	void weightElimW0(double w0);

  protected:
	/**Non-owning constructor: caller keeps the Mlp alive. */
	Error(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& dset);

	/**Owning constructor: Error takes ownership of the Mlp via unique_ptr.
	 * The Mlp is destroyed with the Error.
	 */
	Error(std::unique_ptr<MultiLayerPerceptron::Mlp> mlp, DataTools::DataSet& dset);

	/**Calculate the error for this output.
	 * \param out the output from the MLP.
	 * \param dout the desired output.
	 * \return the error.
	 */
	virtual double outputError(const std::vector<double>& out,
	                           const std::vector<double>& dout) const = 0;

	/**Calculates the gradient of the weight elimination term.
	 * \param wi the weight to regularize.
	 * \return the weight elimination term.
	 */
	double weightElimGrad(double wi) const;

	/**Add the gradient of the weight elimination term to each weight
	 * in the specified interval.
	 * The offset defines the starting index while length
	 * defies the number of elements to update.
	 * \param gradients the gradients to regularize.
	 * \param offset the offset.
	 * \param length the length.
	 */
	void weightElimGrad(std::vector<double>& gradients, const std::vector<double>& weights,
	                    uint offset, uint length) const;

	/**Add the gradient of the weight elimination term to each
	 * gradient except the bias.
	 * \param gradients the gradient vector for the entire Mlp.
	 * \param ncurr the number of neurons in current layer.
	 * \param nprev the number of neurons in previous layer.
	 */
	void weightElimGradLayer(std::vector<double>& gradients, const std::vector<double>& weights,
	                         uint ncurr, uint nprev) const;

	/**Add the gradient of the weight elimination term to each
	 * gradient except the bias.
	 * \param gradients the gradient vector for the entire Mlp.
	 * \param arch the architecture for the Mlp.
	 */
	void weightElimGradMlp(std::vector<double>& gradients, const std::vector<double>& weights,
	                       const std::vector<uint>& arch) const;

	/**Add the gradient of the weight elimination term to each
	 * gradient in the Mlp.
	 * The bias is skipped as usual.
	 */
	void weightElimGrad();

	/**Calculates the weight elimination term.
	 * \return the weight elimination term.
	 */
	double weightElim() const;

	/**Pack a DataSet into the Error's reusable [B x n_in] and [B x n_out]
	 * buffers (row-major). Buffers persist across calls so repeated
	 * gradient()/outputError() invocations don't allocate.
	 * \param dset the DataSet to pack.
	 */
	void packBatch(DataTools::DataSet& dset) const;

	/**Reusable batch input buffer, populated by packBatch. */
	mutable std::vector<double> theInputMatrix;

	/**Reusable batch target buffer, populated by packBatch. */
	mutable std::vector<double> theTargetMatrix;

	/**The Mlp associated with an Error. Always points at the active Mlp,
	 * whether owned (theOwnedMlp set) or borrowed.
	 */
	MultiLayerPerceptron::Mlp* theMlp;

	/**Optional ownership of the Mlp. Set when constructed from a
	 * unique_ptr; null when constructed from a reference.
	 */
	std::unique_ptr<MultiLayerPerceptron::Mlp> theOwnedMlp;

	/**The DataSet associated with an Error.*/
	DataTools::DataSet* theDset;

	/**Controls whether to use weight elimination or not. */
	bool theWeightElimOn;

	/**The importance of the weight elimination term. */
	double theWeightElimAlpha;

	/**Scaling factor typically set to unity. */
	double theWeightElimW0;

  private:
	/**Copy constructor. */
	Error(const Error&);

	/**Assignment operator. */
	Error& operator=(const Error&);
};
} // namespace MultiLayerPerceptron

// ===== mlp/CrossEntropy.hh =====
namespace MultiLayerPerceptron {
/**A class representing the implementation of the Error interface.
 * Only full batch updating is supported. This class represents
 * the Kullback Leibler(Cross Entropy) Error function. Not that this Error function is
 * supposed to be used with class discrimination problems ONLY! Thus in an
 * architechture with only one output I still assume two classes. In the
 * special case of one output and two classes the following will be used:
 * \f[E=-\frac{1}{N}\sum_{n}\left(d_n\ln y_n + (1-d_n)\ln (1-y_n)\right)\f]
 * Otherwise we use:
 * \f[E=-\frac{1}{N}\sum_{n}\sum_{i}\left(d_i\ln\left(\frac{y_i}{d_i}\right)\right)\f]
 */
class CrossEntropy : public Error {
  public:
	/**Non-owning constructor: caller keeps the Mlp alive. */
	CrossEntropy(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& dset);

	/**Owning constructor: this Error takes ownership of the Mlp. */
	CrossEntropy(std::unique_ptr<MultiLayerPerceptron::Mlp> mlp, DataTools::DataSet& dset);

	/**Basic destructor. */
	~CrossEntropy();

	double gradient(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& dset);

	double gradient();

	double outputError(MultiLayerPerceptron::Mlp& mlp, DataTools::DataSet& dset);

	double outputError() const;

  private:
	/**Copy constructor.
	 * \param sse the error to create this object from.
	 */
	CrossEntropy(const CrossEntropy& sse);

	/**Assignment operator.
	 * \param sse the error to copy from.
	 */
	CrossEntropy& operator=(const CrossEntropy& sse);

	/**Calculate the output error for every neuron in the output
	 * layer.
	 * \param ol the output layer.
	 * \param out the output from the MLP.
	 * \param dout the desired output.
	 */
	void localGradient(MultiLayerPerceptron::Layer& ol, const std::vector<double>& out,
	                   const std::vector<double>& dout);

	/**Calculate the local gradient.
	 * \param curr the current layer.
	 * \param next the next layer.
	 */
	void localGradient(MultiLayerPerceptron::Layer& curr, MultiLayerPerceptron::Layer& next);

	/**Back-propagate the output error through the network.
	 * \deprecated Use the backpropagate() instead, since an Mlp is now a
	 * member of the Error interface.
	 * \param mlp the MLP to backpropagate the error through.
	 */
	void backpropagate(MultiLayerPerceptron::Mlp& mlp);

	/**Back-propagate the output error through the network. */
	void backpropagate();

	/**Calculate gradient for the weights in the first layer.
	 * \deprecated Use the gradientBatch instead since Error functions in
	 * NeuralNetHack should only do batch updating. It is up to the Trainer to
	 * divide up DataSet:s as to provide block or online updating.
	 * \param first the first hidden layer with weights.
	 * \param in the input vector.
	 */
	void gradient(MultiLayerPerceptron::Layer& first, std::vector<double>& in);

	/**Calculate gradient for the weights in the first layer. This
	 * does not replace the previous gradients. Instead it adds to new
	 * gradient to the previous one. This is intended for use with the
	 * block version of gradient.
	 * \param first the first hidden layer with weights.
	 * \param in the input vector.
	 */
	void gradientBatch(MultiLayerPerceptron::Layer& first, std::vector<double>& in);

	/**Calculate the gradient between two layers.
	 * \deprecated Use the gradientBatch instead since Error functions in
	 * NeuralNetHack should only do batch updating. It is up to the Trainer to
	 * divide up DataSet:s as to provide block or online updating.
	 * \param curr the current layer.
	 * \param prev the previous layer.
	 */
	void gradient(MultiLayerPerceptron::Layer& curr, MultiLayerPerceptron::Layer& prev);

	/**Calculate the gradient between two layers. This
	 * does not replace the previous gradients. Instead it adds to new
	 * gradient to the previous one. This is intended for use with the
	 * batch version of gradient.
	 * \param curr the current layer.
	 * \param prev the previous layer.
	 */
	void gradientBatch(MultiLayerPerceptron::Layer& curr, MultiLayerPerceptron::Layer& prev);

	double outputError(const std::vector<double>& out, const std::vector<double>& dout) const;

	/**Set all gradients to zero. */
	void killGradients();
};
} // namespace MultiLayerPerceptron

