// ===== mlp/Trainer.hh =====
#include <fstream>
#include <memory>
#include <string>
#include <ostream>
#include <vector>

namespace MultiLayerPerceptron {
/**A base class representing the training of an MLP. */
class Trainer {
  public:
	/**Basic destructor. */
	virtual ~Trainer();

	/**Return a pointer to the Mlp being trained.
	 * \return the mlp pointer.
	 */
	Mlp* mlp();

	/**Set the mlp pointer that shall be trained.
	 * \param mlp the pointer to the mlp that shall be trained.
	 */
	void mlp(Mlp* mlp);

	/**Get the DataSet this Trainer should use for training.
	 * \return the pointer to the DataSet.
	 */
	DataTools::DataSet* data();

	/**Set the DataSet this Trainer should use for training.
	 * \param d the pointer to the DataSet.
	 */
	void data(DataTools::DataSet* d);

	/**Return the error function this Trainer is using.
	 * \return the error function.
	 */
	Error* error();

	/**Set the error function to train this committee with.
	 * \param e the error function.
	 */
	void error(Error* e);

	/**Return the number of epochs to train for.
	 * \return the number of epochs.
	 */
	uint numEpochs() const;

	/**Set the number of epochs to train for.
	 * \param ne the number of epochs.
	 */
	void numEpochs(uint ne);

	/**Return the training error for this trainer. */
	double trainingError() const;

	/**Set the training error for this trainer.
	 * \param te the training error.
	 */
	void trainingError(double te);

	/**Get the batch size for this trainer.
	 * \return the batch size.
	 */
	uint batchSize() const;

	/**Set the batch size for this trainer.
	 * \param bs the batch size.
	 */
	void batchSize(uint bs);

	/**Optional validation DataSet used for the learning-curve file.
	 * Setting this on its own does nothing; pair with learningCurveFile.
	 */
	void validationData(DataTools::DataSet* v);
	DataTools::DataSet* validationData() const;

	/**When set, the trainer writes a gnuplot-friendly learning-curve
	 * file as it trains: one row per recorded epoch, columns
	 * `epoch  trainErr` (and `valErr` when validationData is also set).
	 * Pass an empty string to disable. Cloned trainers do not inherit
	 * the path so they don't all clobber the same file.
	 */
	void learningCurveFile(const std::string& path);
	const std::string& learningCurveFile() const;

	/**Enable validation-loss early stopping. Training stops if the
	 * validation loss has not improved by more than `minDelta` for
	 * `patience` consecutive recorded epochs, and the MLP weights
	 * (including norm params) are restored to the best-val-loss
	 * snapshot. patience=0 disables (default). Requires
	 * validationData to be set; silently no-ops otherwise.
	 */
	void earlyStopping(uint patience, double minDelta = 0.0);
	uint earlyStoppingPatience() const { return theEsPatience; }
	double earlyStoppingMinDelta() const { return theEsMinDelta; }
	bool earlyStopped() const { return theEsTriggered; }

	/**Tells wether this trainer has everything it needs in order to
	 * perform training.
	 * \return true if everything is ready, false if something is missing.
	 */
	bool isValid() const;

	/**Method used to train an MLP. This method sets the member
	 * attributes Mlp and DataSet and then performs training.
	 * \param mlp the MLP to train.
	 * \param dset the data set to train the MLP on.
	 * \param os the ostream to print the training process to.
	 */
	void train(Mlp& mlp, DataTools::DataSet& dset, std::ostream& os);

	/**Method used to train a copy of the current MLP.
	 * This creates a copy of the current
	 * Mlp, trains it and returns it to the caller.
	 * The Error function in the Trainer is the same.
	 * \param dset the data set to train the MLP on.
	 * \param os the ostream to print the training process to.
	 * \return a unique_ptr to the newly trained Mlp.
	 */
	std::unique_ptr<Mlp> trainNew(DataTools::DataSet& dset, std::ostream& os);

	/**Method used to train a copy of the current MLP.
	 * This creates a copy of the current
	 * Mlp, trains it and returns it to the caller.
	 * The DataSet and the Error function in the Trainer is the same.
	 * \param os the ostream to print the training process to.
	 * \return a unique_ptr to the newly trained Mlp.
	 */
	std::unique_ptr<Mlp> trainNew(std::ostream& os);

	/**Method used to train an MLP. This uses the Mlp the DataSet
	 * and the Error function in the Trainer.
	 * \param os the ostream to print the training process to.
	 */
	virtual void train(std::ostream& os) = 0;

	/**Method that clones the Trainer and returns a copy of it.
	 * \return a unique_ptr to the clone of this Trainer.
	 */
	virtual std::unique_ptr<Trainer> clone() const = 0;

  protected:
	/**Non-owning constructor: caller keeps mlp/error alive. */
	Trainer(Mlp& mlp, DataTools::DataSet& data, Error& error, double te, uint bs);

	/**Owning constructor: this Trainer takes ownership of the Error
	 * (and transitively whatever the Error owns, like the Mlp).
	 */
	Trainer(std::unique_ptr<Error> error, DataTools::DataSet& data, double te, uint bs);

	/**Copy constructor.
	 * \param trainer the Trainer object to copy.
	 */
	Trainer(const Trainer& trainer);

	/**Assignment operator.
	 * \param trainer the Trainer object to copy.
	 */
	Trainer& operator=(const Trainer& trainer);

	/**Check if convergence criterion is reached.
	 * \param ecurr the error in the current epoch.
	 * \param eprev the error from the previous epoch.
	 * \return true if criterion is met, false otherwise.
	 */
	bool hasConverged(double ecurr, double eprev) const;

	/**Append one row to the learning-curve file. No-op if no path is
	 * set. Lazy-opens the file on first call (truncating any existing
	 * content) and writes a `# epoch  trainErr [valErr]` header. If
	 * validationData is set, also computes and emits the val error
	 * (restoring the Error's internal mlp/dset pointers afterwards so
	 * subsequent gradient() calls still target the training data).
	 */
	void recordLearningPoint(uint epoch, double trainErr);

	/**Reset the early-stopping bookkeeping. Subclasses must call this
	 * once at the top of their train() implementation. No-op when
	 * patience=0.
	 */
	void resetEarlyStopping();

	/**Update early-stopping state with the current epoch's validation
	 * loss (computed lazily if val data is set). Returns true iff the
	 * subclass should break out of its training loop. When it does,
	 * the best-snapshot weights are automatically restored.
	 */
	bool earlyStopCheck();

	/**The Mlp this Trainer is using. */
	Mlp* theMlp;

	/**The DataSet this Trainer will be using. */
	DataTools::DataSet* theData;

	/**The error function. */
	Error* theError;

	/**Optional ownership of the Error. Set when constructed via the
	 * owning ctor; null when constructed from a reference.
	 */
	std::unique_ptr<Error> theOwnedError;

	/**The number of epochs to train for. */
	uint theNumEpochs;

	/**The error required to stop training. */
	double theTrainingError;

	/**The number of patterns to use every epoch. */
	uint theBatchSize;

	/**Optional non-owning pointer to a validation DataSet. */
	DataTools::DataSet* theValData = nullptr;

	/**Path for the learning-curve file. Empty = disabled. */
	std::string theLearningCurvePath;

	/**Lazy-opened stream for the learning-curve file. */
	std::unique_ptr<std::ofstream> theLearningCurveStream;

	/**Early-stopping config + state. */
	uint theEsPatience = 0;
	double theEsMinDelta = 0.0;
	double theEsBestVal = 0.0;
	uint theEsStaleEpochs = 0;
	bool theEsHasBest = false;
	bool theEsTriggered = false;
	std::vector<double> theEsBestW;
	std::vector<std::vector<double>> theEsBestGammas;
	std::vector<std::vector<double>> theEsBestBetas;

  private:
	void snapshotBestWeights();
	void restoreBestWeights();
};
} // namespace MultiLayerPerceptron

// ===== EnsembleBuilder.hh =====
#include <cstdint>
#include <functional>
#include <memory>

namespace NeuralNetHack {
/**The result of a training session. A training session can
 * include several trainings and Mlp(s).*/
class Session {
  public:
	Session() : ensemble(nullptr), trnData(nullptr), valData(nullptr) {}

	Session(std::unique_ptr<Ensemble> c, std::unique_ptr<DataTools::DataSet> trn,
	        std::unique_ptr<DataTools::DataSet> val)
	    : ensemble(std::move(c)), trnData(std::move(trn)), valData(std::move(val)) {}

	Session(const Session& s)
	    : ensemble(s.ensemble ? std::make_unique<Ensemble>(*s.ensemble) : nullptr),
	      trnData(s.trnData ? std::make_unique<DataTools::DataSet>(*s.trnData) : nullptr),
	      valData(s.valData ? std::make_unique<DataTools::DataSet>(*s.valData) : nullptr) {}

	Session(Session&&) noexcept = default;

	~Session() = default;

	Session& operator=(const Session& s) {
		if (this != &s) {
			ensemble = s.ensemble ? std::make_unique<Ensemble>(*s.ensemble) : nullptr;
			trnData = s.trnData ? std::make_unique<DataTools::DataSet>(*s.trnData) : nullptr;
			valData = s.valData ? std::make_unique<DataTools::DataSet>(*s.valData) : nullptr;
		}
		return *this;
	}

	Session& operator=(Session&&) noexcept = default;

	/**The ensemble that holds all the models. */
	std::unique_ptr<Ensemble> ensemble;

	/**The DataSet used for training. */
	std::unique_ptr<DataTools::DataSet> trnData;

	/**The DataSet used for validation. */
	std::unique_ptr<DataTools::DataSet> valData;
};

/**A base class representing the different ensemble builders.
 * \sa CrossSplitter, Bagger
 */
class EnsembleBuilder {
  public:
	EnsembleBuilder();
	EnsembleBuilder(const EnsembleBuilder&) = delete;
	EnsembleBuilder& operator=(const EnsembleBuilder&) = delete;
	EnsembleBuilder(EnsembleBuilder&&) noexcept = default;
	EnsembleBuilder& operator=(EnsembleBuilder&&) noexcept = default;
	virtual ~EnsembleBuilder();

	/**Accessor for the Trainer (read-only). */
	MultiLayerPerceptron::Trainer* trainer() const;

	/**Take ownership of a Trainer. */
	void trainer(std::unique_ptr<MultiLayerPerceptron::Trainer> t);

	/**Accessor for the Sampler (read-only). */
	DataTools::Sampler* sampler() const;

	/**Take ownership of a Sampler. */
	void sampler(std::unique_ptr<DataTools::Sampler> s);

	/**Set a factory that returns a fresh, fully-owned Trainer for each
	 * ensemble member. When set, `buildEnsemble` parallelises member
	 * training; without a factory it falls back to serial training using
	 * the single shared Trainer set via `trainer()`.
	 *
	 * The factory receives the per-member training DataSet. Required if
	 * you want OpenMP-parallel ensemble training, since a single Trainer
	 * holds mutable state (Mlp weights, Adam moments, ...) that would
	 * race across threads.
	 */
	using TrainerFactory =
	    std::function<std::unique_ptr<MultiLayerPerceptron::Trainer>(DataTools::DataSet&)>;
	void trainerFactory(TrainerFactory f);

	/**Base seed for per-member RNG seeding inside parallel buildEnsemble.
	 * Each iteration seeds its worker's thread-local RNG with
	 * baseSeed + member_index, so weight init is deterministic and
	 * diverse across members regardless of thread scheduling.
	 */
	void baseSeed(uint64_t s);

	/**Base path for per-member learning-curve files. When set, each
	 * ensemble member's trainer writes a gnuplot-friendly file named
	 * `<stem>_<NNN>.<ext>` (NNN = zero-padded member index, 1-based).
	 * The member's out-of-bag DataSet (samples[i].second) is wired up
	 * as validation so the file gets a `valErr` column too. Empty
	 * disables. Setter on its own does nothing without a sampler that
	 * yields meaningful out-of-bag splits (Bootstrap, CrossSplit, ...).
	 */
	void learningCurvePathBase(const std::string& base);
	const std::string& learningCurvePathBase() const;

	/**Accessor for the Session vector.
	 * \return the Session vector.
	 */
	std::vector<Session>& sessions();

	/**Mutator for the Session vector.
	 * \param s the Session vector to set.
	 */
	void sessions(std::vector<Session>& s);

	/**Method that will fetch the ensemble that was built previously.
	 * \return the built ensemble.
	 */
	Ensemble* getEnsemble();

	/**Method that will build the ensemble using the current Sampler.
	 * \sa Sampler
	 * \return the built ensemble.
	 */
	Ensemble* buildEnsemble();

  private:
	/**Utility to check whether everything is ok. This checks so that
	 * all pointers are pointing at something.
	 * \return true if good to go, false otherwise.
	 */
	bool isValid() const;

	/**Owned Trainer. */
	std::unique_ptr<MultiLayerPerceptron::Trainer> theTrainer;

	/**Owned Sampler. */
	std::unique_ptr<DataTools::Sampler> theSampler;

	/**Optional factory for building a fresh Trainer per member. */
	TrainerFactory theTrainerFactory;

	/**Base seed for per-member RNG seeding under parallel training. */
	uint64_t theBaseSeed{1};

	/**Base path for per-member learning-curve files (empty = disabled). */
	std::string theLearningCurvePathBase;

	/**A vector of Estimations. */
	std::vector<Session> theSessions;
};
} // namespace NeuralNetHack

