// ===== mlp/Adam.hh =====
#include <vector>

namespace MultiLayerPerceptron {
/**Adam/AdamW optimizer.
 * Uses per-weight adaptive learning rates with first and second moment
 * estimates. When weightDecay > 0, implements decoupled weight decay (AdamW).
 */
class Adam : public Trainer {
  public:
	Adam(Mlp& mlp, DataTools::DataSet& data, Error& error, double te, uint bs, double lr = 0.001,
	     double beta1 = 0.9, double beta2 = 0.999, double eps = 1e-8, double weightDecay = 0.0);

	/**Owning constructor: takes ownership of the Error. */
	Adam(std::unique_ptr<Error> error, DataTools::DataSet& data, double te, uint bs,
	     double lr = 0.001, double beta1 = 0.9, double beta2 = 0.999, double eps = 1e-8,
	     double weightDecay = 0.0);
	~Adam();

	void train(std::ostream& os) override;
	std::unique_ptr<Trainer> clone() const override;

	double learningRate() const;
	void learningRate(double lr);

  private:
	Adam(const Adam& a);
	Adam& operator=(const Adam& a);

	double trainEpoch(DataTools::DataSet& dset);
	bool buildBlock(DataTools::DataSet& blockData, uint& cntr) const;

	double theLearningRate;
	double theBeta1;
	double theBeta2;
	double theEpsilon;
	double theWeightDecay;

	std::vector<double> theM; // first moment
	std::vector<double> theV; // second moment
	uint theTimestep;
};
} // namespace MultiLayerPerceptron

// ===== mlp/GradientDescent.hh =====
namespace MultiLayerPerceptron {
/**A class representing the implementation of the Trainer interface.
 * This learning algorithm is called Gradient Descent and
 * uses only first order gradients of the error function.
 * The weight update rule:
 * \f[\omega_{t+1}=\omega_t - \eta_t\cdot\frac{\partial E}
 * {\partial\omega_t} + \alpha\cdot\Delta\omega_t\f] where
 * \f[ \eta_{t+1} = \left\{\begin{array}{ll}
 * \eta_t * \gamma, & E_{t+1}>E_t;\\
 * \eta_t * \left(1+\frac{1-\gamma}{10}\right), & otherwise;
 * \end{array}\right. \f]
 */
class GradientDescent : public Trainer {

  public:
	/**Basic constructor.
	 * \param mlp the Mlp to train.
	 * \param data the DataSet to use.
	 * \param error the Error function to use.
	 * \param te the training error at which to stop training.
	 * \param bs the batch size.
	 * \param lr the learning rate.
	 * \param dlr the decrease of learning rate.
	 * \param m the momentum term.
	 */
	GradientDescent(Mlp& mlp, DataTools::DataSet& data, Error& error, double te, uint bs, double lr,
	                double dlr, double m);

	/**Owning constructor: takes ownership of the Error (and via the Error,
	 * the Mlp). Lifetimes are bundled into the trainer.
	 */
	GradientDescent(std::unique_ptr<Error> error, DataTools::DataSet& data, double te, uint bs,
	                double lr, double dlr, double m);

	/**Basic destructor. */
	~GradientDescent();

	/**Method used to train an MLP. This uses the Mlp and the DataSet
	 * in the Trainer.
	 */
	void train(std::ostream& os);

	/**Set the learning rate for this trainer.
	 * \param lr the learning rate.
	 */
	void learningRate(double lr);

	/**Set the decrease of learning rate for this trainer.
	 * \param dlr the learning rate.
	 */
	void decLearningRate(double dlr);

	/**Set the momentum for this trainer.
	 * \param m the momentum term.
	 */
	void momentum(double m);

	/**Return the batch size for this trainer. */
	uint batchSize();

	/**Return the learning rate this trainer is using. */
	double learningRate() const;

	/**Return the decrease of learning rate this trainer is using. */
	double decLearningRate() const;

	/**Return the momentum term this trainer is using. */
	double momentum() const;

	std::unique_ptr<Trainer> clone() const override;

  private:
	/**Copy constructor.
	 * \param gd the object to copy from.
	 */
	GradientDescent(const GradientDescent& gd);

	/**Assignment operator.
	 * \param gd the object to assign from.
	 */
	GradientDescent& operator=(const GradientDescent& gd);

	/**Method used to train an MLP during one epoch.
	 * \param dset the data set to train the MLP on.
	 */
	double train(DataTools::DataSet& dset);

	/**Updates the learning rate.
	 * \f[ \eta_{t+1} = \left\{\begin{array}{ll}
	 * \eta_t * \gamma, & E_{t+1}>E_t;\\
	 * \eta_t * \left(1+\frac{1-\gamma}{10}\right), & otherwise;
	 * \end{array}\right. \f]
	 */
	void updateLearningRate(double err, double prevErr);

	/**Build the block update DataSet.
	 * \param blockData the DataSet that will contain the new block.
	 * \param cntr the cntr of where we last left off in the original DataSet.
	 * \return true if cntr was resest, false otherwise.
	 */
	bool buildBlock(DataTools::DataSet& blockData, uint& cntr) const;

	/**The learning rate. */
	double theLearningRate;

	/**The decrease of the learning rate.
	 * This governs how much the learning rate should be decreased
	 * when training error goes up. The value is typically close to
	 * but always less than 1.0.
	 */
	double theDecLearningRate;

	/**The momentum term.
	 * This governs how much of the previous weight update should be
	 * included in the current update. This value is typically set
	 * between 0.8 and 0.99. Never more than 1.0.
	 */
	double theMomentum;
};
} // namespace MultiLayerPerceptron

// ===== mlp/QuasiNewton.hh =====
#include <ostream>

namespace MultiLayerPerceptron {
/**A class implementing the L-BFGS quasi-Newton optimization algorithm.
 * Uses limited-memory BFGS which stores only the last M (s,y) pairs
 * instead of the full n*n inverse Hessian approximation.
 * Memory: O(M*n) instead of O(n^2). Compute: O(M*n) instead of O(n^2).
 *
 * The weight update rule:
 * \f[\omega_{t+1}=\omega_t + \alpha_t H_t g_t\f]
 * Where \f$ H_t \f$ is the L-BFGS approximation of the inverse Hessian
 * computed via the two-loop recursion, and \f$ g \f$ is the gradient.
 */
class QuasiNewton : public Trainer {

  public:
	/**Basic constructor.
	 * \param mlp the Mlp to train.
	 * \param data the DataSet to use.
	 * \param error the Error function to use.
	 * \param te the training error at which to stop training.
	 * \param bs the batch size.
	 */
	QuasiNewton(Mlp& mlp, DataTools::DataSet& data, Error& error, double te, uint bs);

	/**Owning constructor: takes ownership of the Error. */
	QuasiNewton(std::unique_ptr<Error> error, DataTools::DataSet& data, double te, uint bs);

	/**Basic destructor. */
	~QuasiNewton();

	/**Method used to train an MLP. This uses the Mlp and the DataSet
	 * in the Trainer.
	 */
	void train(std::ostream& os);

	std::unique_ptr<Trainer> clone() const override;

  private:
	/**Copy constructor.
	 * \param qn the object to copy from.
	 */
	QuasiNewton(const QuasiNewton& qn);

	/**Assignment operator.
	 * \param qn the object to assign from.
	 */
	QuasiNewton& operator=(const QuasiNewton& qn);

	/**Reset all the vectors in the L-BFGS algorithm. */
	void resetVectors();

	/**Compute the L-BFGS search direction via the two-loop recursion.
	 * Result is placed in dir (= H_k * grad).
	 * \param grad the current gradient vector.
	 * \param dir the resulting search direction.
	 */
	void lbfgsDirection(const std::vector<double>& grad, std::vector<double>& dir);

	/**Store a new (s,y) pair in the circular history buffer.
	 * s = w - wPrev, y = g - gPrev. Skips if curvature condition not met.
	 */
	void storeHistory();

	/**Finds out the step length we want to use with our quasi newton
	 * direction. This calls mnbrak and brent.
	 * \param alpha the step length we want to use.
	 * \return the error function evaluated at alpha.
	 */
	float findAlpha(float& alpha);

	/**Brackets the minima.
	 * \param ax the leftmost value for the x values.
	 * \param bx the middle value for the x values.
	 * \param cx the rightmost value for the x values.
	 * \param fa the value of the function at ax.
	 * \param fb the value of the function at bx.
	 * \param fc the value of the function at cx.
	 */
	void mnbrak(float* ax, float* bx, float* cx, float* fa, float* fb, float* fc);

	/**An implementation of brents line search.
	 * \param ax the leftmost value for the x values.
	 * \param bx the middle value for the x values.
	 * \param cx the rightmost value for the x values.
	 * \param tol the tolerance.
	 * \param xmin the x value corresponding to the minimum.
	 * \return the error function evaluated at xmin.
	 */
	float brent(float ax, float bx, float cx, float tol, float* xmin);

	/**Calculate the error associated with a certain alfa.
	 * \param alfa the quasi newton step length.
	 * \return the error.
	 */
	float err(float alfa);

	/**L-BFGS history size (number of (s,y) pairs to store). */
	static constexpr uint LBFGS_M = 20;

	/**Number of weights. */
	uint nWeights;

	/**The weight vector at t+1. */
	std::vector<double> w;

	/**The weight vector at t. */
	std::vector<double> wPrev;

	/**The gradient vector at t+1. */
	std::vector<double> g;

	/**The gradient vector at t. */
	std::vector<double> gPrev;

	/**The change in the weight vector (s_k). */
	std::vector<double> dw;

	/**The change in the gradient vector (y_k). */
	std::vector<double> dg;

	/**Temporary vector for search direction (H*g). */
	std::vector<double> vectorTemp1;

	/**Temporary vector for line search evaluation. */
	std::vector<double> vectorTemp2;

	// L-BFGS history (circular buffer)

	/**History of weight changes s_k = w_{k+1} - w_k. */
	std::vector<std::vector<double>> sHistory;

	/**History of gradient changes y_k = g_{k+1} - g_k. */
	std::vector<std::vector<double>> yHistory;

	/**History of rho_k = 1 / (y_k^T * s_k). */
	std::vector<double> rhoHistory;

	/**Number of (s,y) pairs currently stored. */
	uint historyCount;

	/**Start index in the circular buffer. */
	uint historyStart;
};
} // namespace MultiLayerPerceptron

