#include <vector>
#include <map>
#include <utility>
#include <iostream>
#include <fstream>
#include <iomanip>
#include <string>

using namespace NeuralNetHack;
using namespace DataTools;
using namespace EvalTools;
using std::cerr;
using std::endl;
using std::make_pair;
using std::map;
using std::ofstream;
using std::pair;
using std::setw;
using std::string;
using std::vector;

// PUBLIC

ModelSelector::ModelSelector() {}

ModelSelector::~ModelSelector() {}

pair<Config, double> ModelSelector::findBestModel(DataSet& trnData, Config& config) {
	Config bestConfig = config;
	Config tmpConfig = config;
	double bestAuc = 0;
	map<string, vector<double>>& vary = config.vary();
	vector<double> alphas = sequence(vary["WeightElim"]);

	// Create output file and print header
	string fname = "msresult." + config.suffix() + ".txt";
	ofstream of(fname.c_str());
	of << "#" << setw(13) << "Alpha" << setw(14) << "TrnAUC" << setw(14) << "ValAUC" << endl;

	// Print results for all values of alpha and save the best
	for (vector<double>::iterator it = alphas.begin(); it != alphas.end(); ++it) {
		tmpConfig.weightElimAlpha(*it);
		pair<double, double>* auc = trainAndValidateModel(trnData, tmpConfig);
		of << setw(14) << tmpConfig.weightElimAlpha() << setw(14) << auc->first << setw(14)
		   << auc->second << endl;
		if (auc->second > bestAuc) {
			bestConfig = tmpConfig;
			bestAuc = auc->second;
		}
		delete auc;
	}
	of.close();

	return make_pair(bestConfig, bestAuc);
}

// PRIVATE

/* Return the cross-validated error for a specific model */
pair<double, double>* ModelSelector::trainAndValidateModel(DataSet& trnData, const Config& config) {

	pair<double, double>* auc = 0;

	if (config.msParamN() > 0) {
		auto me = Factory::createModelEstimator(config, trnData);
		auc = me->runAndEstimateModel(&ErrorMeasures::auc);
		// Use 632 rule if bootstrap was used.
		if (config.msParamDataSelection() == "boot") {
			auc->second = Auc632PlusRule(auc->first, auc->second);
		}
	} else {
		cerr << "Can't do model selection without MSParam set" << endl;
		abort();
	}
	return auc;
}

vector<double> ModelSelector::sequence(const vector<double>& seq) {
	double nextval = seq[0];
	vector<double> res;
	while (nextval <= seq[1]) {
		res.push_back(nextval);
		nextval += seq[2];
	}
	return res;
}

double ModelSelector::Auc632PlusRule(double meanTrn, double meanTst) {
	double r = 0;
	if (meanTrn > meanTst && meanTst > 0.5) r = (meanTst - meanTrn) / (0.5 - meanTrn);
	double w = 0.632 / (1.0 - 0.368 * r);
	double meanTstPrime = (meanTst > 0.5) ? meanTst : 0.5;
	return (1.0 - w) * meanTrn + w * meanTstPrime;
}

// ===== datatools/DataManager.cc =====
#include <algorithm>
#include <cassert>
#include <cmath>
#include <iostream>
#include <iterator>
#include <numeric>

using namespace DataTools;
using namespace std;

static auto& rng() {
	return nnh::rand::generator();
}

DataManager::DataManager() : indices(vector<uint>(0)), isRandom(true) {}

DataManager::DataManager(const DataManager& ds) {
	*this = ds;
}

DataManager::~DataManager() {}

DataManager& DataManager::operator=(const DataManager& ds) {
	if (this != &ds) {
		indices = ds.indices;
		isRandom = ds.isRandom;
	}
	return *this;
}

bool DataManager::random() const {
	return isRandom;
}

void DataManager::random(bool rnd) {
	isRandom = rnd;
}

pair<DataSet, DataSet> DataManager::split(DataSet& ds, double ratio) {
	assert(ratio < 1.0 && ratio > 0.0);
	uint n = ds.size();
	uint nTraining = (uint)nearbyint(ratio * n);
	DataSet training(ds);
	DataSet validation(ds);

	indices = ds.indices();
	if (isRandom) shuffle(indices.begin(), indices.end(), rng());

	training.indices().assign(indices.begin(), indices.begin() + nTraining);
	validation.indices().assign(indices.begin() + nTraining, indices.end());

	return {std::move(training), std::move(validation)};
}

vector<DataSet> DataManager::split(DataSet& ds, uint k) {
	uint n = ds.size();
	uint nInEachPart = n / k;
	uint nLeft = n % k;
	assert(k > 0 && k <= n);
	if (k < 2) {
		cerr << "Warning: DataManager::split(): split with k<2." << endl;
		return {ds};
	}
	vector<DataSet> splits(k);

	indices = ds.indices();
	if (isRandom) shuffle(indices.begin(), indices.end(), rng());

	vector<uint> tmpIndices;
	auto indexIterator = indices.begin();
	for (uint i = 0; i < splits.size(); ++i, indexIterator += nInEachPart) {
		tmpIndices.assign(indexIterator, indexIterator + nInEachPart);
		DataSet d(ds);
		d.indices(tmpIndices);
		splits[i] = std::move(d);
	}

	auto splitIterator = splits.begin();
	for (uint i = 0; i < nLeft; ++i, ++splitIterator, ++indexIterator)
		splitIterator->indices().push_back(*indexIterator);

	return splits;
}

pair<DataSet, DataSet> DataManager::split(DataSet& ds) {
	uint n = ds.size();
	DataSet trn(ds);
	DataSet val(ds);
	vector<uint> origInd = ds.indices();
	buildIndicesWithReplacement(origInd);
	assert(origInd.size() == indices.size());
	if (isRandom) shuffle(indices.begin(), indices.end(), rng());
	trn.indices(indices);

	sort(origInd.begin(), origInd.end());
	sort(indices.begin(), indices.end());
	vector<uint> valInd(n);
	valInd.erase(set_difference(origInd.begin(), origInd.end(), indices.begin(), indices.end(),
	                            valInd.begin()),
	             valInd.end());
	if (isRandom) shuffle(valInd.begin(), valInd.end(), rng());
	val.indices(valInd);

	return {std::move(trn), std::move(val)};
}

DataSet DataManager::join(vector<DataSet>& splits) {
	assert(splits.size());
	if (splits.size() < 2) return splits.front();

	indices.clear();
	vector<DataSet>::iterator its;
	for (its = splits.begin(); its != splits.end(); ++its) {
		vector<uint>& tmp = its->indices();
		indices.insert(indices.end(), tmp.begin(), tmp.end());
	}
	DataSet d(splits.front());
	d.indices(indices);
	return d;
}

// PRIVATE-----------------------------------------------------------------------

void DataManager::buildIndices(uint n) {
	indices = vector<uint>(n);
	iota(indices.begin(), indices.end(), 0);
	shuffle(indices.begin(), indices.end(), rng());
}

void DataManager::buildIndicesWithReplacement(uint n) {
	indices.clear();

	for (uint i = 0; i < n; ++i) {
		uint index = (uint)nearbyint((n - 1) * nnh::rand::uniform());
		indices.push_back(index);
	}
}

void DataManager::buildIndicesWithReplacement(vector<uint>& orig) {
	indices.clear();

	uint n = orig.size();
	for (uint i = 0; i < n; ++i) {
		uint index = (uint)nearbyint((n - 1) * nnh::rand::uniform());
		indices.push_back(orig.at(index));
	}
}

void DataManager::printIndices(ostream& os) {
	assert(os);
	copy(indices.begin(), indices.end(), ostream_iterator<uint>(os, " "));
	os << endl;
}

// ===== datatools/Normaliser.cc =====
#include <cmath>
#include <cassert>
#include <cstdlib>
#include <algorithm>

using namespace DataTools;
using namespace std;

Normaliser::Normaliser() : theStdDev(0), theMean(0), theSkip(0) {}

Normaliser::Normaliser(std::vector<double>& stds, std::vector<double>& means,
                       std::vector<bool>& skips)
    : theStdDev(stds), theMean(means), theSkip(skips) {}

Normaliser::Normaliser(const Normaliser& n) {
	*this = n;
}

Normaliser::~Normaliser() {}

Normaliser& Normaliser::operator=(const Normaliser& n) {
	if (this != &n) {
		theStdDev = n.theStdDev;
		theMean = n.theMean;
		theSkip = n.theSkip;
	}
	return *this;
}

DataSet& Normaliser::normalise(DataSet& d) {
	if (d.nInput() + d.nOutput() != theMean.size()) {
		cerr << "Error: mean vector length and input data length differ!" << endl;
		abort();
	}
	for (uint i = 0; i < d.size(); ++i)
		normalise(d.pattern(i));
	if (theSkip.size() > 0) transformBinaryCoding(d);
	return d;
}

DataSet& Normaliser::calcAndNormalise(DataSet& d, bool doSkip) {
	theMean = vector<double>(d.nInput() + d.nOutput(), 0);
	theStdDev = vector<double>(d.nInput() + d.nOutput(), 0);
	calcMean(d);
	calcStdDev(d);

	if (doSkip) {
		theSkip = vector<bool>(d.nInput() + d.nOutput(), true);
		findSkip(d);
		transformBinaryCoding(d);
		for (uint i = 0; i < theSkip.size(); ++i)
			if (theSkip[i]) {
				theMean[i] = 0;
				theStdDev[i] = 1;
			}
	}

	for (uint i = 0; i < d.size(); ++i)
		normalise(d.pattern(i));
	return d;
}

/** Subtracts the mean from each variable and then divides it with the corresponding standard
 * deviation.
 */
struct SubtractAndDivide {
	vector<double>::const_iterator itm;
	vector<double>::const_iterator its;
	SubtractAndDivide(vector<double>::const_iterator m, vector<double>::const_iterator s)
	    : itm(m), its(s) {}
	void operator()(double& x) {
		double diff = abs(x - *itm);
		if (diff > 1e-15)
			x = (x - *itm) / *its;
		else
			x = 0;
		++itm;
		++its;
	}
};

/** Multiplies each variable with its standard deviation and then adds its
 * mean.
 */
struct MultiplyAndAdd {
	vector<double>::const_iterator itm;
	vector<double>::const_iterator its;
	MultiplyAndAdd(vector<double>::const_iterator m, vector<double>::const_iterator s)
	    : itm(m), its(s) {}
	void operator()(double& x) {
		x = x * *its++ + *itm++;
		if (fabs(x) < 1e-15) x = 0;
	}
};

Pattern& Normaliser::normalise(Pattern& p) {
	for_each(p.input().begin(), p.input().end(),
	         SubtractAndDivide(theMean.begin(), theStdDev.begin()));
	for_each(p.output().begin(), p.output().end(),
	         SubtractAndDivide(theMean.begin() + p.nInput(), theStdDev.begin() + p.nInput()));
	return p;
}

vector<double>& Normaliser::normaliseInput(vector<double>& i) {
	for_each(i.begin(), i.end(), SubtractAndDivide(theMean.begin(), theStdDev.begin()));
	transformBinaryCoding(i);
	return i;
}

DataSet& Normaliser::unnormalise(DataSet& d) {
	assert(theMean.size() == theStdDev.size());
	assert(theMean.size() == (d.nInput() + d.nOutput()));

	for (uint i = 0; i < d.size(); ++i)
		unnormalise(d.pattern(i));
	return d;
}

Pattern& Normaliser::unnormalise(Pattern& p) {
	for_each(p.input().begin(), p.input().end(),
	         MultiplyAndAdd(theMean.begin(), theStdDev.begin()));
	for_each(p.output().begin(), p.output().end(),
	         MultiplyAndAdd(theMean.begin() + p.nInput(), theStdDev.begin() + p.nInput()));
	return p;
}

vector<double>& Normaliser::stdDev() {
	return theStdDev;
}

void Normaliser::stdDev(vector<double>& s) {
	theStdDev = s;
}

vector<double>& Normaliser::mean() {
	return theMean;
}

void Normaliser::mean(vector<double>& m) {
	theMean = m;
}

vector<bool>& Normaliser::skip() {
	return theSkip;
}

void Normaliser::skip(vector<bool>& m) {
	theSkip = m;
}

// PRIVATE---------------------------------------------------------------------//

void Normaliser::calcMean(DataSet& d) {
	for (uint i = 0; i < d.size(); ++i) {
		Pattern& p = d.pattern(i);
		vector<double>& in = p.input();
		vector<double>& out = p.output();
		uint k = 0;
		for (uint j = 0; j < in.size(); ++j, ++k)
			theMean[k] += in[j];
		for (uint j = 0; j < out.size(); ++j, ++k)
			theMean[k] += out[j];
	}
	double n = d.size();
	for (uint i = 0; i < theMean.size(); ++i)
		theMean[i] = theMean[i] / n;
}

void Normaliser::calcStdDev(DataSet& d) {
	for (uint i = 0; i < d.size(); ++i) {
		Pattern& p = d.pattern(i);
		vector<double>& in = p.input();
		vector<double>& out = p.output();
		uint k = 0;
		for (uint j = 0; j < in.size(); ++j, ++k)
			theStdDev[k] += pow(in[j] - theMean[k], 2);
		for (uint j = 0; j < out.size(); ++j, ++k)
			theStdDev[k] += pow(out[j] - theMean[k], 2);
	}
	double n = d.size();
	for (uint i = 0; i < theStdDev.size(); ++i)
		theStdDev[i] = sqrt(theStdDev[i] / n);
}

void Normaliser::findSkip(DataSet& d) {
	for (uint i = 0; i < d.size(); ++i) {
		Pattern& p = d.pattern(i);
		vector<double>& in = p.input();
		vector<double>& out = p.output();
		uint k = 0;
		for (uint j = 0; j < in.size(); ++j, ++k)
			theSkip[k] = (theSkip[k] && skipBin(in[j])) || (theSkip[k] && skipSig(in[j]));
		for (uint j = 0; j < out.size(); ++j, ++k)
			theSkip[k] = (theSkip[k] && skipBin(out[j])) || (theSkip[k] && skipSig(out[j]));
	}
}

bool Normaliser::skipBin(double val) const {
	double e = 1e-15;
	return ((fabs(val - 1) <= e) || (fabs(val) <= e));
}

bool Normaliser::skipSig(double val) const {
	double e = 1e-15;
	return ((fabs(val - 1) <= e) || (fabs(val + 1) <= e));
}

void Normaliser::transformBinaryCoding(DataSet& data) {
	for (uint i = 0; i < data.size(); ++i) {
		vector<double>& in = data.pattern(i).input();
		uint k = 0;
		for (uint j = 0; j < in.size(); ++j, ++k)
			if (theSkip[k] == true && in[j] == 0) in[j] = -1;
	}
}

void Normaliser::transformBinaryCoding(vector<double>& input) {
	for (uint j = 0; j < input.size(); ++j)
		if (theSkip[j] == true && input[j] == 0) input[j] = -1;
}

