// ===== evaltools/Gof.cc =====
#include <vector>
#include <cassert>
#include <algorithm>
#include <utility>

using namespace EvalTools;
using std::pair;
using std::vector;

// PUBLIC

Gof::Gof(uint nb) : numBins(nb) {}

double Gof::goodnessOfFit(const vector<double>& output, const vector<uint>& target) {
	assert(output.size() == target.size());
	uint numInBin = output.size() / numBins;
	uint leftOvers = output.size() % numBins;
	double chi2 = 0;
	vector<pair<double, uint>> sortedVec = doSort(output, target);
	vector<uint> n;

	for (uint i = 0; i < numBins; ++i)
		n.push_back(numInBin);
	for (uint i = 0; i < leftOvers; ++i)
		n[i]++;
	uint id = 0;
	for (uint i = 0; i < numBins; ++i) {
		double sum1 = 0, sum2 = 0;
		for (uint j = 0; j < n[i]; ++j) {
			// std::cerr<<std::endl<<id<<"\t"<<sortedVec[id].second<<"\t"<<sortedVec[id].first;
			sum1 += sortedVec[id].second;
			sum2 += sortedVec[id++].first;
		}
		sum2 /= (double)n[i];

		double tmp = (sum1 - n[i] * sum2) * (sum1 - n[i] * sum2) / (n[i] * sum2 * (1.0 - sum2));
		chi2 += tmp;

		/*
		   std::cout<<std::endl<<tmp<<" = "<<"("<<sum1<<" - "<<n[i]<<" * "<<sum2<<") * ("<<
		   sum1<<" - "<<n[i]<<" * "<<sum2<<") / ("<<n[i]<<" * "<<sum2<<" *(1.0 - "<<sum2<<"))";
		*/
	}

	return chi2;
}

// PRIVATE

vector<pair<double, uint>> Gof::doSort(const vector<double>& output, const vector<uint>& target) {
	assert(output.size() == target.size());
	vector<pair<double, uint>> sortedVec;

	for (uint i = 0; i < output.size(); ++i) {
		sortedVec.push_back(std::make_pair(output[i], target[i]));
	}
	std::sort(sortedVec.begin(), sortedVec.end());
	return sortedVec;
}

// ===== matrixtools/MatrixTools.cc =====
#ifdef USE_BLAS
extern "C" {
#include <cblas.h>
}
#endif

#include <cassert>
#include <algorithm>
#include <iostream>
#include <iterator>

using namespace MatrixTools;
using namespace std;

typedef vector<double>::iterator ditor;

// VECTOR FUNCTIONS------------------------------------------------------------//

void MatrixTools::add(vector<double>& v1, vector<double>& v2) {
	assert(v1.size() == v2.size());
#ifdef USE_BLAS
	cblas_daxpy(v1.size(), 1.0, v2.data(), 1, v1.data(), 1);
#else
	transform(v1.begin(), v1.end(), v2.begin(), v1.begin(), plus<double>());
#endif
}

void MatrixTools::add(vector<double>& v1, vector<double>& v2, vector<double>& res) {
	assert(v1.size() == v2.size() && v1.size() == res.size());
#ifdef USE_BLAS
	cblas_dcopy(v1.size(), v1.data(), 1, res.data(), 1);
	cblas_daxpy(res.size(), 1.0, v2.data(), 1, res.data(), 1);
#else
	transform(v1.begin(), v1.end(), v2.begin(), res.begin(), plus<double>());
#endif
}

void MatrixTools::sub(vector<double>& v1, vector<double>& v2) {
	assert(v1.size() == v2.size());
#ifdef USE_BLAS
	cblas_daxpy(v1.size(), -1.0, v2.data(), 1, v1.data(), 1);
#else
	transform(v1.begin(), v1.end(), v2.begin(), v1.begin(), minus<double>());
#endif
}

void MatrixTools::sub(vector<double>& v1, vector<double>& v2, vector<double>& res) {
	assert(v1.size() == v2.size() && v1.size() == res.size());
#ifdef USE_BLAS
	cblas_dcopy(v1.size(), v1.data(), 1, res.data(), 1);
	cblas_daxpy(res.size(), -1.0, v2.data(), 1, res.data(), 1);
#else
	transform(v1.begin(), v1.end(), v2.begin(), res.begin(), minus<double>());
#endif
}

void MatrixTools::mul(vector<double>& vec, double scalar) {
#ifdef USE_BLAS
	cblas_dscal(vec.size(), scalar, vec.data(), 1);
#else
	const uint n = vec.size();
	double* __restrict__ v = vec.data();
	for (uint i = 0; i < n; ++i)
		v[i] *= scalar;
#endif
}

void MatrixTools::mul(vector<double>& vec, double scalar, vector<double>& res) {
	assert(vec.size() == res.size());
#ifdef USE_BLAS
	cblas_dcopy(vec.size(), vec.data(), 1, res.data(), 1);
	cblas_dscal(res.size(), scalar, res.data(), 1);
#else
	const uint n = vec.size();
	const double* __restrict__ v = vec.data();
	double* __restrict__ r = res.data();
	for (uint i = 0; i < n; ++i)
		r[i] = v[i] * scalar;
#endif
}

void MatrixTools::div(vector<double>& vec, double scalar) {
	mul(vec, 1.0 / scalar);
}

void MatrixTools::div(vector<double>& vec, double scalar, vector<double>& res) {
	mul(vec, 1.0 / scalar, res);
}

double MatrixTools::innerProduct(vector<double>& v1, vector<double>& v2) {
#ifdef USE_BLAS
	return cblas_ddot(v1.size(), v1.data(), 1, v2.data(), 1);
#else
	return inner_product(v1.begin(), v1.end(), v2.begin(), (double)0);
#endif
}

void MatrixTools::outerProduct(vector<double>& v1, vector<double>& v2,
                               vector<vector<double>>& res) {
	assert((v1.size() == res.size()) && (v2.size() == res[0].size()));
	for (uint i = 0; i < v1.size(); ++i)
		for (uint j = 0; j < v2.size(); ++j)
			res[i][j] = v1[i] * v2[j];
}

vector<vector<double>> MatrixTools::outerProduct(vector<double>& v1, vector<double>& v2) {
	vector<vector<double>> res = matrix(v1.size(), v2.size());
	for (uint i = 0; i < v1.size(); ++i)
		for (uint j = 0; j < v2.size(); ++j)
			res[i][j] = v1[i] * v2[j];
	return res;
}

void MatrixTools::print(vector<double>& v) {
	copy(v.begin(), v.end(), ostream_iterator<double>(cout, " "));
}

void MatrixTools::print(vector<uint>& v) {
	copy(v.begin(), v.end(), ostream_iterator<uint>(cout, " "));
}

// MATRIX FUNCTIONS------------------------------------------------------------//

vector<vector<double>> MatrixTools::matrix(uint row, uint col) {
	return vector<vector<double>>(row, vector<double>(col, 0));
}

vector<vector<double>> MatrixTools::identity(uint n) {
	vector<vector<double>> res(n, vector<double>(n, 0));
	for (uint i = 0; i < n; ++i)
		res[i][i] = 1;
	return res;
}

void MatrixTools::add(vector<vector<double>>& m1, vector<vector<double>>& m2) {
	assert(m1.size() == m2.size());
	assert(m1[0].size() == m2[0].size());
	for (uint i = 0; i < m1.size(); ++i)
		for (uint j = 0; j < m1[i].size(); ++j)
			m1[i][j] = m1[i][j] + m2[i][j];
}

void MatrixTools::add(vector<vector<double>>& m1, vector<vector<double>>& m2,
                      vector<vector<double>>& res) {
	assert(m1.size() == res.size());
	assert(m1[0].size() == res[0].size());
	assert(m2.size() == res.size());
	assert(m2[0].size() == res[0].size());
	for (uint i = 0; i < m1.size(); ++i)
		for (uint j = 0; j < m1[i].size(); ++j)
			res[i][j] = m1[i][j] + m2[i][j];
}

void MatrixTools::sub(vector<vector<double>>& m1, vector<vector<double>>& m2) {
	assert(m1.size() == m2.size());
	assert(m1[0].size() == m2[0].size());
	for (uint i = 0; i < m1.size(); ++i)
		for (uint j = 0; j < m1[i].size(); ++j)
			m1[i][j] = m1[i][j] - m2[i][j];
}

void MatrixTools::sub(vector<vector<double>>& m1, vector<vector<double>>& m2,
                      vector<vector<double>>& res) {
	assert(m1.size() == res.size());
	assert(m1[0].size() == res[0].size());
	assert(m2.size() == res.size());
	assert(m2[0].size() == res[0].size());
	for (uint i = 0; i < m1.size(); ++i)
		for (uint j = 0; j < m1[i].size(); ++j)
			res[i][j] = m1[i][j] - m2[i][j];
}

void MatrixTools::mul(vector<vector<double>>& m, double scale) {
	for (uint i = 0; i < m.size(); ++i)
		for (uint j = 0; j < m[i].size(); ++j)
			m[i][j] = m[i][j] * scale;
}

void MatrixTools::mul(vector<vector<double>>& m, double scale, vector<vector<double>>& res) {
	assert(m.size() == res.size());
	assert(m[0].size() == res[0].size());
	for (uint i = 0; i < m.size(); ++i)
		for (uint j = 0; j < m[i].size(); ++j)
			res[i][j] = m[i][j] * scale;
}

void MatrixTools::mul(vector<vector<double>>& m, vector<double>& v, vector<double>& res) {
	assert(v.size() == res.size());
	assert(m[0].size() == v.size());
	res.assign(res.size(), 0);
#ifdef USE_BLAS
	// Row-by-row dot product (matrix rows are not contiguous across rows)
	for (uint i = 0; i < m.size(); ++i)
		res[i] = cblas_ddot(m[i].size(), m[i].data(), 1, v.data(), 1);
#else
	for (uint i = 0; i < m.size(); ++i)
		for (uint j = 0; j < m[i].size(); ++j)
			res[i] += m[i][j] * v[j];
#endif
}

vector<double> MatrixTools::mul(vector<vector<double>>& m, vector<double>& v) {
	assert(m[0].size() == v.size());
	vector<double> res(v.size(), 0);
#ifdef USE_BLAS
	for (uint i = 0; i < m.size(); ++i)
		res[i] = cblas_ddot(m[i].size(), m[i].data(), 1, v.data(), 1);
#else
	for (uint i = 0; i < m.size(); ++i)
		for (uint j = 0; j < m[i].size(); ++j)
			res[i] += m[i][j] * v[j];
#endif
	return res;
}

void MatrixTools::mul(vector<double>& v, vector<vector<double>>& m, vector<double>& res) {
	assert(v.size() == res.size());
	assert(m.size() == v.size());
	res.assign(res.size(), 0);
	for (uint i = 0; i < m[0].size(); ++i)
		for (uint j = 0; j < m.size(); ++j)
			res[i] += m[j][i] * v[j];
}

vector<double> MatrixTools::mul(vector<double>& v, vector<vector<double>>& m) {
	assert(m.size() == v.size());
	vector<double> res(v.size(), 0);
	for (uint i = 0; i < m[0].size(); ++i)
		for (uint j = 0; j < m.size(); ++j)
			res[i] += m[j][i] * v[j];
	return res;
}

void MatrixTools::div(vector<vector<double>>& m, double scale) {
	for (uint i = 0; i < m.size(); ++i)
		for (uint j = 0; j < m[i].size(); ++j)
			m[i][j] = m[i][j] / scale;
}

void MatrixTools::div(vector<vector<double>>& m, double scale, vector<vector<double>>& res) {
	assert(m.size() == res.size());
	assert(m[0].size() == res[0].size());
	for (uint i = 0; i < m.size(); ++i)
		for (uint j = 0; j < m[i].size(); ++j)
			res[i][j] = m[i][j] / scale;
}

void MatrixTools::print(vector<vector<double>>& m) {
	for (uint i = 0; i < m.size(); ++i) {
		copy(m[i].begin(), m[i].end(), ostream_iterator<double>(cout, " "));
		cout << endl;
	}
}

// ===== mlp/Activation.cc =====
#include <cmath>
#include <stdexcept>

namespace MultiLayerPerceptron {

// Vectorisable polynomial tanh / sigmoid for the batch path.
//
// libm's scalar tanh / exp ate ~25% of training time on profile because gcc
// auto-vectorisation didn't pick libmvec siblings even with -ffast-math +
// `omp simd`. Replaced with branchless polynomial approximations that the
// compiler vectorises trivially. Accuracy: tanh better than 1e-7 on
// [-3, 3] and saturates correctly outside; sigmoid is derived from the
// same tanh, accurate to ~5e-8 over the working range. Both well within
// training noise. Scalar fire() still uses libm for exactness.
namespace {
inline double fast_tanh(double x) {
	const double xc = x < -5.0 ? -5.0 : (x > 5.0 ? 5.0 : x);
	const double x2 = xc * xc;
	const double a = xc * (135135.0 + x2 * (17325.0 + x2 * (378.0 + x2)));
	const double b = 135135.0 + x2 * (62370.0 + x2 * (3150.0 + x2 * 28.0));
	return a / b;
}

inline double fast_sigmoid(double x) {
	return 0.5 * (fast_tanh(0.5 * x) + 1.0);
}
} // namespace

// Tag <-> string round-trip ---------------------------------------------------

Activation activationFromTag(std::string_view tag) {
	if (tag == SIGMOID) return Sigmoid{};
	if (tag == TANHYP) return TanH{};
	if (tag == LINEAR) return Linear{};
	if (tag == RELU) return ReLU{};
	if (tag == LEAKYRELU) return LeakyReLU{};
	if (tag == ELU_ACT) return ELU{};
	throw std::invalid_argument(std::string("activationFromTag: unknown tag '") +
	                            std::string(tag) + "'");
}

const std::string& activationToTag(const Activation& a) {
	static const std::string kSigmoid = SIGMOID;
	static const std::string kTanH = TANHYP;
	static const std::string kLinear = LINEAR;
	static const std::string kReLU = RELU;
	static const std::string kLeakyReLU = LEAKYRELU;
	static const std::string kELU = ELU_ACT;
	struct V {
		const std::string& operator()(Sigmoid) const { return kSigmoid; }
		const std::string& operator()(TanH) const { return kTanH; }
		const std::string& operator()(Linear) const { return kLinear; }
		const std::string& operator()(ReLU) const { return kReLU; }
		const std::string& operator()(LeakyReLU) const { return kLeakyReLU; }
		const std::string& operator()(ELU) const { return kELU; }
	};
	return std::visit(V{}, a);
}

// Scalar fire -----------------------------------------------------------------

double fire(Sigmoid, double lif) {
	return 1.0 / (1.0 + std::exp(-lif));
}
double fire(TanH, double lif) {
	return std::tanh(lif);
}
double fire(Linear, double lif) {
	return lif;
}
double fire(ReLU, double lif) {
	return lif > 0.0 ? lif : 0.0;
}
double fire(LeakyReLU a, double lif) {
	return lif > 0.0 ? lif : a.alpha * lif;
}
double fire(ELU a, double lif) {
	return lif > 0.0 ? lif : a.alpha * (std::exp(lif) - 1.0);
}

// Scalar firePrime (from local induced field) ---------------------------------

double firePrime(Sigmoid s, double lif) {
	const double f = fire(s, lif);
	return f * (1.0 - f);
}
double firePrime(TanH t, double lif) {
	const double f = fire(t, lif);
	return 1.0 - f * f;
}
double firePrime(Linear, double) {
	return 1.0;
}
double firePrime(ReLU, double lif) {
	return lif > 0.0 ? 1.0 : 0.0;
}
double firePrime(LeakyReLU a, double lif) {
	return lif > 0.0 ? 1.0 : a.alpha;
}
double firePrime(ELU a, double lif) {
	return lif > 0.0 ? 1.0 : a.alpha * std::exp(lif);
}

// Scalar firePrime (from cached output y = fire(lif)) -------------------------

double firePrimeFromOutput(Sigmoid, double y) {
	return y * (1.0 - y);
}
double firePrimeFromOutput(TanH, double y) {
	return 1.0 - y * y;
}
double firePrimeFromOutput(Linear, double) {
	return 1.0;
}
double firePrimeFromOutput(ReLU, double y) {
	return y > 0.0 ? 1.0 : 0.0;
}
double firePrimeFromOutput(LeakyReLU a, double y) {
	return y > 0.0 ? 1.0 : a.alpha;
}
double firePrimeFromOutput(ELU a, double y) {
	return y >= 0.0 ? 1.0 : y + a.alpha;
}

// Scalar firePrimePrime (from local induced field) ----------------------------

double firePrimePrime(Sigmoid s, double lif) {
	const double f = fire(s, lif);
	const double fp = f * (1.0 - f);
	return fp - 2.0 * f * fp;
}
double firePrimePrime(TanH t, double lif) {
	const double f = fire(t, lif);
	return 2.0 * f * (f * f - 1.0);
}
double firePrimePrime(Linear, double) {
	return 0.0;
}
double firePrimePrime(ReLU, double) {
	return 0.0;
}
double firePrimePrime(LeakyReLU, double) {
	return 0.0;
}
double firePrimePrime(ELU a, double lif) {
	return lif > 0.0 ? 0.0 : a.alpha * std::exp(lif);
}

// Scalar firePrimePrime (from cached output) ----------------------------------

double firePrimePrimeFromOutput(Sigmoid, double y) {
	const double fp = y * (1.0 - y);
	return fp - 2.0 * y * fp;
}
double firePrimePrimeFromOutput(TanH, double y) {
	return 2.0 * y * (y * y - 1.0);
}
double firePrimePrimeFromOutput(Linear, double) {
	return 0.0;
}
double firePrimePrimeFromOutput(ReLU, double) {
	return 0.0;
}
double firePrimePrimeFromOutput(LeakyReLU, double) {
	return 0.0;
}
double firePrimePrimeFromOutput(ELU a, double y) {
	return y >= 0.0 ? 0.0 : y + a.alpha;
}

// Batch activation ------------------------------------------------------------

void applyActivation(Sigmoid, double* __restrict__ out, ActivationSize n) {
#pragma omp simd
	for (ActivationSize i = 0; i < n; ++i)
		out[i] = fast_sigmoid(out[i]);
}

void applyActivation(TanH, double* __restrict__ out, ActivationSize n) {
#pragma omp simd
	for (ActivationSize i = 0; i < n; ++i)
		out[i] = fast_tanh(out[i]);
}

void applyActivation(Linear, double* __restrict__, ActivationSize) {
	// identity
}

void applyActivation(ReLU, double* __restrict__ out, ActivationSize n) {
	for (ActivationSize i = 0; i < n; ++i)
		out[i] = out[i] > 0.0 ? out[i] : 0.0;
}

void applyActivation(LeakyReLU a, double* __restrict__ out, ActivationSize n) {
	const double alpha = a.alpha;
	for (ActivationSize i = 0; i < n; ++i)
		out[i] = out[i] > 0.0 ? out[i] : alpha * out[i];
}

void applyActivation(ELU a, double* __restrict__ out, ActivationSize n) {
	const double alpha = a.alpha;
#pragma omp simd
	for (ActivationSize i = 0; i < n; ++i)
		out[i] = out[i] > 0.0 ? out[i] : alpha * (std::exp(out[i]) - 1.0);
}

// Batch derivative scaling ----------------------------------------------------

void applyDerivScale(Sigmoid, const double* __restrict__ out, double* __restrict__ deltas,
                     ActivationSize n) {
	for (ActivationSize i = 0; i < n; ++i)
		deltas[i] *= out[i] * (1.0 - out[i]);
}

void applyDerivScale(TanH, const double* __restrict__ out, double* __restrict__ deltas,
                     ActivationSize n) {
	for (ActivationSize i = 0; i < n; ++i)
		deltas[i] *= (1.0 - out[i] * out[i]);
}

void applyDerivScale(Linear, const double* __restrict__, double* __restrict__, ActivationSize) {
	// f'(x) = 1, deltas unchanged
}

void applyDerivScale(ReLU, const double* __restrict__ out, double* __restrict__ deltas,
                     ActivationSize n) {
	for (ActivationSize i = 0; i < n; ++i)
		deltas[i] *= (out[i] > 0.0 ? 1.0 : 0.0);
}

void applyDerivScale(LeakyReLU a, const double* __restrict__ out, double* __restrict__ deltas,
                     ActivationSize n) {
	const double alpha = a.alpha;
	for (ActivationSize i = 0; i < n; ++i)
		deltas[i] *= (out[i] > 0.0 ? 1.0 : alpha);
}

void applyDerivScale(ELU a, const double* __restrict__ out, double* __restrict__ deltas,
                     ActivationSize n) {
	const double alpha = a.alpha;
	for (ActivationSize i = 0; i < n; ++i)
		deltas[i] *= (out[i] >= 0.0 ? 1.0 : out[i] + alpha);
}

} // namespace MultiLayerPerceptron

