#include <cassert>

using namespace NeuralNetHack;
using namespace MultiLayerPerceptron;
using namespace MatrixTools;
using std::make_unique;
using std::unique_ptr;
using std::vector;

Ensemble::Ensemble() : theEnsemble(), theScales() {}

Ensemble::Ensemble(Mlp& mlp, double s) : theEnsemble(), theScales(1, s) {
	theEnsemble.push_back(make_unique<Mlp>(mlp));
}

Ensemble::Ensemble(const Ensemble& c) : theScales(c.theScales) {
	theEnsemble.reserve(c.theEnsemble.size());
	for (const auto& m : c.theEnsemble)
		theEnsemble.push_back(make_unique<Mlp>(*m));
}

Ensemble::~Ensemble() = default;

Ensemble& Ensemble::operator=(const Ensemble& c) {
	if (this != &c) {
		theEnsemble.clear();
		theEnsemble.reserve(c.theEnsemble.size());
		for (const auto& m : c.theEnsemble)
			theEnsemble.push_back(make_unique<Mlp>(*m));
		theScales = c.theScales;
	}
	return *this;
}

Mlp& Ensemble::operator[](const uint i) {
	return mlp(i);
}

Mlp& Ensemble::mlp(const uint i) {
	assert(i < theEnsemble.size());
	return *(theEnsemble[i]);
}

const Mlp& Ensemble::mlp(const uint i) const {
	assert(i < theEnsemble.size());
	return *(theEnsemble[i]);
}

void Ensemble::delMlp(const uint i) {
	assert(i < theEnsemble.size());
	theEnsemble.erase(theEnsemble.begin() + i);
	theScales.erase(theScales.begin() + i);
}

void Ensemble::addMlp(Mlp& mlp, double s) {
	theEnsemble.push_back(make_unique<Mlp>(mlp));
	theScales.push_back(s);
}

void Ensemble::addMlp(Mlp& mlp) {
	theEnsemble.push_back(make_unique<Mlp>(mlp));
	theScales.assign(theEnsemble.size(), 1.0 / theEnsemble.size());
}

void Ensemble::addMlp(unique_ptr<Mlp> mlp, double s) {
	theEnsemble.push_back(std::move(mlp));
	theScales.push_back(s);
}

void Ensemble::addMlp(unique_ptr<Mlp> mlp) {
	theEnsemble.push_back(std::move(mlp));
	theScales.assign(theEnsemble.size(), 1.0 / theEnsemble.size());
}

double Ensemble::scale(const uint i) const {
	assert(i < theScales.size());
	return theScales[i];
}

void Ensemble::scale(const uint i, double s) {
	assert(i < theScales.size());
	theScales[i] = s;
}

uint Ensemble::size() const {
	return theEnsemble.size();
}

vector<double> Ensemble::propagate(const vector<double>& input) {
	assert(theEnsemble.size() == theScales.size());
	assert(!theEnsemble.empty());
	auto itm = theEnsemble.begin();
	auto its = theScales.begin();
	vector<double> output = (*itm)->propagate(input);
	++itm;
	mul(output, *its++);
	for (; itm != theEnsemble.end(); ++itm) {
		vector<double> tmp = (*itm)->propagate(input);
		mul(tmp, *its++);
		add(output, tmp, output);
	}
	return output;
}

// ===== FeatureSelector.cc =====
#include <utility>
#include <fstream>
#include <iostream>
#include <functional>
#include <vector>
#include <map>
#include <algorithm>
#include <string>
#include <iterator>

using namespace NeuralNetHack;
using DataTools::CoreDataSet;
using DataTools::DataSet;
using DataTools::Normaliser;
using DataTools::Sampler;
using NeuralNetHack::Parser;
using std::cerr;
using std::cout;
using std::divides;
using std::endl;
using std::ifstream;
using std::ios;
using std::map;
using std::ofstream;
using std::ostream_iterator;
using std::pair;
using std::set_difference;
using std::string;
using std::transform;
using std::vector;

FeatureSelector::FeatureSelector(uint minf, uint maxf, uint maxr)
    : minFeatures(minf), maxFeatures(maxf), maxRemove(maxr) {}

// template<class T>
Config FeatureSelector::run(Config& config, double (*f)(Ensemble&, DataSet&)) {
	cout << "Running FeatureSelector with min: " << minFeatures << " max: " << maxFeatures
	     << " maxRemove: " << maxRemove << endl;
	best = config;
	bool stop = false;
	ModelSelector ms;
	vector<pair<double, vector<uint>>> results;
	string s = "featuresel." + best.suffix() + ".txt";
	ofstream os(s.c_str());
	os << "AUC\tInputs" << endl;
	// cerr<<"Before while"<<endl;
	// cerr.flush();

	while (!stop) {
		DataSet trnData, tstData;
		// cerr<<"Parse Data"<<endl;
		// cerr.flush();
		parseData(best, trnData, tstData);
		// cerr<<"Create sampler"<<endl;
		// cerr.flush();
		auto sampler = Factory::createSampler(best, trnData);
		// cerr<<"Create effects"<<endl;
		// cerr.flush();
		vector<double> effects(
		    best.inputColumns().size()); // Storing the effect removing and index has on AUC
		double meanAuc = 0;
		// cerr<<"Before 2nd while"<<endl;
		// cerr.flush();
		while (sampler->hasNext()) {
			// cerr<<"Finding optimal model"<<endl;
			// cerr.flush();
			//  Find optimal parameters for ensemble
			auto sample = sampler->next();
			DataSet trn = sample.first, val = sample.second;
			pair<Config, double> msres = ms.findBestModel(sample.first, best);
			// cerr<<"Building optimal model"<<endl;
			// cerr.flush();
			//  Build optimal ensemble
			auto eb = Factory::createEnsembleBuilder(msres.first, sample.first);
			std::unique_ptr<Ensemble> e(eb->buildEnsemble());
			double auc = (*f)(*e, sample.second);
			storeClampingEffect(*e, val, auc, effects, f);
			meanAuc += auc;
		}
		// cerr<<"Store and print performance"<<endl;
		// cerr.flush();
		//  Store and print the performance for these variables
		meanAuc = meanAuc / sampler->howMany();
		results.push_back(make_pair(meanAuc, best.inputColumns()));
		os << meanAuc << "\t";
		copy(best.inputColumns().begin(), best.inputColumns().end(),
		     ostream_iterator<double>(os, " "));
		os << endl;

		// cerr<<"Remove redundant variables"<<endl;
		// cerr.flush();
		//  Remove redundant variables
		{
			double d = effects.size();
			for (auto& e : effects)
				e /= d;
		}
		cerr << "Effects: ";
		copy(effects.begin(), effects.end(), ostream_iterator<double>(cerr, " "));
		cerr << endl;
		vector<uint> toRemove = removeFeatures(effects, best.inputColumns());
		vector<uint> toKeep;
		vector<uint> indices = best.inputColumns();
		// cerr<<"Calc set difference"<<endl;
		// cerr.flush();
		set_difference(indices.begin(), indices.end(), toRemove.begin(), toRemove.end(),
		               back_inserter(toKeep));
		// cerr<<"Set variables to keep"<<endl;
		// cerr.flush();
		best.inputColumns(toKeep);
		best.inputColumnsT(toKeep);
		vector<uint> tmp = best.architecture();
		tmp[0] = toKeep.size();
		best.architecture(tmp);

		// cerr<<"Check stop condition"<<endl;
		// cerr.flush();
		// Check stop condition
		// TODO improve this so that we continue removing features until we hit minFeatures.
		if (best.inputColumns().size() < maxFeatures) {
			stop = true;
		}
	}
	os.close();
	return best;
}

// PRIVATE

vector<uint> FeatureSelector::removeFeatures(std::vector<double>& effects,
                                             const std::vector<uint>& inputs) {
	vector<uint> indices; // the indices to remove
	map<double, uint> order;

	for (uint i = 0; i < effects.size(); ++i)
		order[effects[i]] = inputs[i];
	for (map<double, uint>::iterator i = order.begin(); i != order.end(); ++i) {
		// cerr<<"Value: "<<i->first<<" Index: "<<i->second<<endl;
		uint index = i->second;
		if (indices.size() >= maxRemove) break;
		indices.push_back(index);
	}
	sort(indices.begin(), indices.end());
	// cerr<<"Features to remove: ";
	// copy(indices.begin(), indices.end(), ostream_iterator<uint>(cerr, " "));
	// cerr<<endl;
	return indices;
}

void FeatureSelector::parseData(Config& config, DataSet& trnData, DataSet& tstData) {
	ifstream trnStream;
	ifstream tstStream;
	auto trnCoreData = std::make_shared<CoreDataSet>();
	auto tstCoreData = std::make_shared<CoreDataSet>();

	trnStream.open(config.fileName().c_str(), ios::in);
	if (!trnStream || trnStream.bad() || trnStream.fail() || trnStream.eof()) {
		cerr << "Could not open data file: " << config.fileName() << endl;
		abort();
	}
	Parser::readDataFile(trnStream, config.idColumn(), config.inputColumns(),
	                     config.outputColumns(), config.rowRange(), *trnCoreData);
	trnStream.close();
	trnData.coreDataSet(trnCoreData);

	tstStream.open(config.fileNameT().c_str(), ios::in);
	if (!tstStream) {
		cerr << "Could not open data file: " << config.fileNameT() << endl;
		abort();
	}
	Parser::readDataFile(tstStream, config.idColumnT(), config.inputColumnsT(),
	                     config.outputColumnsT(), config.rowRangeT(), *tstCoreData);
	tstStream.close();
	tstData.coreDataSet(tstCoreData);

	Normaliser norm;
	cout << "Normalizing data" << endl;
	if (config.normalization() == "Z") {
		norm.calcAndNormalise(trnData, true);
		norm.normalise(tstData);
	}
}

// template<class T>
void FeatureSelector::storeClampingEffect(Ensemble& e, DataSet& d, double auc,
                                          vector<double>& aucImpact,
                                          double (*f)(Ensemble&, DataSet&)) {
	for (uint i = 0; i < d.nInput(); ++i) {
		// Get original value and mean value for index i
		vector<double> origValues;
		origValues.reserve(d.size());
		for (uint j = 0; j < d.size(); ++j)
			origValues.push_back(d.pattern(j).input()[i]);
		double meanValue = mean(d, i);

		for (uint j = 0; j < d.size(); ++j)
			d.pattern(j).input()[i] = meanValue;
		double newAuc = (*f)(e, d);
		aucImpact[i] += (auc - newAuc);
		// cerr<<"Impact "<<i<<": "<<aucImpact[i]<<endl;
		// cerr.flush();
		for (uint j = 0; j < d.size(); ++j)
			d.pattern(j).input()[i] = origValues[j];
	}
}

double FeatureSelector::mean(DataSet& d, uint index) {
	double mean = 0;
	for (uint i = 0; i < d.size(); ++i)
		mean += d.pattern(i).input()[index];
	return mean / (double)d.size();
}

// ===== OddsRatio.cc =====
#include <algorithm>
#include <functional>
#include <iostream>

using namespace NeuralNetHack;
using DataTools::DataSet;
using DataTools::Pattern;
using MultiLayerPerceptron::Layer;
using MultiLayerPerceptron::Mlp;

using std::cerr;
using std::cout;
using std::endl;
using std::ostream;
using std::plus;
using std::vector;

// Effective odds ratio calculations

vector<double> OddsRatio::oddsRatio(Ensemble& committee, DataSet& data) {
	vector<double> oddsrat(data.nInput(), 0);

	for (uint i = 0; i < data.size(); ++i) {
		vector<double> tmp = oddsRatio(committee, data.pattern(i));
		transform(oddsrat.begin(), oddsrat.end(), tmp.begin(), oddsrat.begin(), plus<double>());
	}
	for (vector<double>::iterator it = oddsrat.begin(); it != oddsrat.end(); ++it)
		(*it) /= (double)data.size();
	return oddsrat;
}

template <class T> struct or_calc {
	or_calc(Ensemble& e, std::vector<T>& i) : ens(e), input(i), oddsrat(0) {
		oddsrat.reserve(input.size());
	}
	void operator()(T& x) {
		T inc = 0.1;
		T p0 = ens.propagate(input).front();
		x += inc;
		T p1 = ens.propagate(input).front();
		x -= inc;
		oddsrat.push_back((p1 * (1 - p0)) / (p0 * (1 - p1)));
	}
	Ensemble& ens;
	std::vector<T>& input;
	std::vector<T> oddsrat;
};

vector<double> OddsRatio::oddsRatio(Ensemble& committee, Pattern& pattern) {
	vector<double>& input = pattern.input();
	struct or_calc<double> ret =
	    for_each(input.begin(), input.end(), or_calc<double>(committee, input));
	return ret.oddsrat;
}

// Utilities like printing and stuff

void OddsRatio::print(ostream& os, vector<double>& oddsrat) {
	if (!os) {
		cerr << "OddsRatio::print: Problem with output stream." << endl;
		return;
	}

	os << "Input\tOR" << endl;
	for (uint i = 0; i < oddsrat.size(); ++i)
		os << i << "\t" << oddsrat[i] << endl;
}

